window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["map"]={"updatedAt":"2026-07-09","count":264,"nodes":[{"id":"cam-dia-huyet-sac-thi-luyen","name":"Cấm địa (khu Huyết sắc thí luyện)","cn":"","capDo":"vuc","parentId":null,"blurb":"Nơi diễn ra Huyết sắc thí luyện, chứa thiên địa linh vật ở khu trung tâm.","detail":"Khu cấm địa diễn ra Huyết sắc thí luyện, chứa nhiều thiên địa linh vật và linh dược tập trung ở khu trung tâm. Nhiều tu sĩ các tông môn va chạm tranh đoạt, tử vong liên tục; các nhóm tiến nhanh vào trung tâm để đục nước béo cò.","theLucLienQuan":["Linh thú sơn","Cự kiếm môn","Hoàng Phong cốc","Thiên khuyết bảo"],"nguon":["@c0181"]},{"id":"o-long-dam","name":"Ô long đàm","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Thủy đàm nước trời sinh dị chất, lạnh vô cùng khiến xung quanh như mùa đông.","detail":"Thủy đàm trong cấm địa, nước trời sinh dị chất, lạnh vô cùng làm quanh đàm như mùa đông. Nhờ đặc tính này, bươm bướm cảnh giới sợ lạnh của Linh thú sơn không thả được ở đây; việc Hàn Lập từng dừng chân tại Ô long đàm đã vô tình giúp hắn tránh một tai kiếp mà không hề hay biết.","theLucLienQuan":[],"nguon":["@c0181"]},{"id":"vach-nui-co-quai","name":"Vách núi cổ quái","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Nơi Hàn Lập tìm thấy hai thi thể đồng quy vu tận.","detail":"Một vách núi cổ quái trong cấm địa, nơi Hàn Lập phát hiện hai thi thể thê thảm: một đệ tử Cự kiếm môn áo đen bị cắt đứt cổ và một sư huynh Hoàng Phong cốc áo vàng bị cự kiếm ghim xuống đất, kết cục của trận tử chiến không người thắng.","theLucLienQuan":[],"nguon":["@c0181"]},{"id":"thai-nhac-son-mach","name":"Thái Nhạc sơn mạch","cn":"","capDo":"khac","parentId":null,"blurb":"Dãy núi nơi Hàn Lập từng thả Vân sí điểu tự do hoạt động.","detail":"Dãy sơn mạch được nhắc trong hồi ức của Hàn Lập: khi vào Hoàng Phong cốc, hắn thả Vân sí điểu tự do trong Thái Nhạc sơn mạch để tránh gây chú ý, về sau chim hoàn toàn hoang dã một đi không trở lại.","theLucLienQuan":[],"nguon":["@c0181","@c0217","@c0347"]},{"id":"trung-tam-cam-dia-huyet-sac-thi-luyen","name":"Trung tâm cấm địa (Huyết Sắc thí luyện)","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Khu trung tâm cấm địa có kỳ hoa dị quả thiên địa linh vật, được yêu thú bậc một cường đại bảo hộ và cấm chế vây khốn kẻ vào sâu.","detail":"Trung tâm cấm địa Huyết Sắc thí luyện có kỳ hoa dị quả thiên địa linh vật, được yêu thú bậc một cường đại (ngang đệ tử đỉnh cao Trúc Cơ kỳ) bảo hộ. Mỗi khi giết yêu thú lấy thuốc, chỗ đó lại sinh linh dược và yêu thú mới xuất hiện khó hiểu, không nhất định cùng loại. Có cấm chế vây khốn hoặc giết kẻ vào sâu, nên đệ tử các phái chỉ dám ở rìa thu thập.","theLucLienQuan":["Hóa Đao Ổ","Thanh Hư môn"],"nguon":["@c0182"]},{"id":"nhat-tuyen-thien","name":"Nhất tuyến thiên","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Vị trí hiểm ác trong cấm địa: hai bên là vách núi cao vòi vọi, chỉ có một con đường nhỏ thông tới khu trung tâm.","detail":"Do cấm địa tuyệt cấm ngự khí phi hành nên tu sĩ buộc đi bộ theo đường nhỏ; chỗ giao nhau tại Nhất tuyến thiên dễ bị chặn cả trước lẫn sau — là nơi Hàn Lập bị hai tu sĩ phục kích một địch hai.","theLucLienQuan":[],"nguon":["@c0183"]},{"id":"cam-dia-huyet-sac-thi-luyen-khu","name":"Cấm địa (khu truyền tống thí luyện)","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Khu vực đệ tử các phái được truyền tống ngẫu nhiên vào; tuyệt cấm ngự khí phi hành; có linh dược khiến mọi người tranh giành, có thời hạn tồn tại rồi mới ra ngoài.","detail":"Trong cấm địa, bay qua sẽ bỏ mạng nên tu sĩ phải đi bộ theo đường nhỏ. Nơi tập trung linh dược quý khiến các tu sĩ tranh đoạt lẫn nhau; kẻ phục kích còn tính kế trốn chờ hết thời gian tồn tại của cấm địa rồi mới ra ngoài an toàn.","theLucLienQuan":[],"nguon":["@c0183"]},{"id":"khu-rung-ram-nhat-tuyen-thien","name":"Khu rừng rậm","capDo":"khac","parentId":null,"blurb":"Khu rừng rậm nơi phục kích giết người tốt; Hàn Lập tới nghỉ tạm khôi phục pháp lực sau trận chiến.","detail":"Sau khi rời Nhất tuyến thiên, Hàn Lập đi một hồi tới khu rừng rậm — nơi thích hợp phục kích giết người — quyết định tìm chỗ nghỉ tạm khôi phục pháp lực đã tổn thất.","nguon":["@c0184"]},{"id":"dong-suoi-nho-phu-can-trung-tam","name":"Dòng suối nhỏ khu phụ cận trung tâm","cn":"","capDo":"khac","parentId":"trung-tam-cam-dia-huyet-sac-thi-luyen","blurb":"Dòng suối nhỏ ở khu phụ cận trung tâm cấm địa, nơi Hàn Thiên Nhai giết nữ đệ tử Yểm nguyệt tông.","detail":"Nằm ở khu phụ cận khu trung tâm huyết sắc thí luyện; bên dòng suối này Hàn Thiên Nhai lừa và giết nữ đệ tử Yểm nguyệt tông.","theLucLienQuan":[],"nguon":["@c0185"]},{"id":"khu-trung-tam-vung-phia-tay","name":"Khu trung tâm — vùng phía tây","capDo":"khac","parentId":"trung-tam-cam-dia-huyet-sac-thi-luyen","blurb":"Hố đất sản sinh kỳ trân dị thảo Hỏa Long thảo ở phía tây khu trung tâm, nơi ba tu sĩ diệt Hỏa lang ba mắt.","detail":"Vùng phía tây khu trung tâm có một hố đất mọc kỳ trân dị thảo; tại đây ba tu sĩ khác môn phái hợp sức diệt Hỏa lang ba mắt để hái Hỏa Long thảo mọc sau thi thể yêu thú.","theLucLienQuan":["Cự Kiếm môn"],"nguon":["@c0191"]},{"id":"khu-trung-tam-vung-phia-nam","name":"Khu trung tâm — vùng phía nam","capDo":"khac","parentId":"trung-tam-cam-dia-huyet-sac-thi-luyen","blurb":"Vùng toàn cát vàng ở phía nam khu trung tâm, nơi Yểm Nguyệt tông truy sát và cô gái áo lục ẩn nấp dưới cát.","detail":"Phía nam khu trung tâm là một vùng nơi nơi đều là cát vàng; cặp đệ tử Yểm Nguyệt tông lùng sục nơi đây bằng Băng Trùy thuật và phù lục, còn cô gái áo lục Linh Thú sơn ẩn mình dưới cát để thoát nạn.","theLucLienQuan":["Yểm Nguyệt tông","Linh thú sơn"],"nguon":["@c0191"]},{"id":"khu-trung-tam-huyet-sac-thi-luyen","name":"Khu vực trung tâm Huyết sắc thí luyện","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Vùng trung tâm của Huyết sắc thí luyện, bao bọc bởi tường đá phong hệ cấm pháp, chỉ vào được qua bốn cánh cửa đồng.","detail":"Vùng trung tâm được bao quanh bởi tường đá cao có phong hệ cấm pháp; ai cố nhảy tường sẽ bị cắt thành mảnh nhỏ, nên bốn cánh cửa đồng khắc minh ấn cổ văn đặt ở bốn phương là lối vào duy nhất. Bên trong là một mảng tiên cảnh đầy kỳ hoa dị thảo — cúc bạc to lớn, quái thụ đỏ, linh khí nồng đậm như động thiên phúc địa, một con đường đá vụn hiện ra khi thảo mộc uốn theo gió.","theLucLienQuan":[],"nguon":["@c0192"]},{"id":"buc-tuong-da-ba-tu-thi","name":"Bức tường đá ba tử thi","cn":"","capDo":"khac","parentId":"khu-trung-tam-huyet-sac-thi-luyen","blurb":"Bức tường đá cao vài trượng gần cửa đồng, trên đó ba tử thi bị đóng đinh xếp thành chữ đại.","detail":"Tường đá cao vài trượng hơi nghiêng nằm gần một cánh cửa đồng vào khu trung tâm. Trên tường có ba người ăn mặc khác nhau bị đại băng trùy đâm xuyên tứ chi, xếp thành chữ đại, đã chết vì mất máu — cảnh giết gà dọa khỉ lập uy nhằm dọa người không dám vào cổng.","theLucLienQuan":[],"nguon":["@c0192"]},{"id":"khu-trung-tam-huyet-sac-thi-luyen-vao","name":"Khu vực trung tâm (lối vào)","cn":"","capDo":"khac","parentId":"khu-trung-tam-huyet-sac-thi-luyen","blurb":"Nơi Hàn Lập vừa tiến vào để kiếm thuốc; trước cửa có bức tường với “kiệt tác” máu thịt do Hàn Thiên Nhai tạo ra.","detail":"Khu vực trung tâm của Huyết sắc thí luyện, chốn tân đệ tử tiến vào tìm dược. Trước cửa có bức tường được nhắc tới với cảnh máu thịt ghê rợn, được Chung Ngô gọi là “kiệt tác” do Hàn Thiên Nhai làm ra.","theLucLienQuan":[],"nguon":["@c0193"]},{"id":"tang-thu-nhat-hoa-vien","name":"Tầng thứ nhất (hoa viên)","capDo":"khac","parentId":"khu-trung-tam-huyet-sac-thi-luyen","blurb":"Khu ngoài cùng của khu trung tâm cấm địa, đẹp như tranh với hoa thảo thụ mộc nhưng ít vật hữu dụng cho tu tiên.","detail":"Tầng thứ nhất trong ba tầng vỏ-thịt-hạt của khu trung tâm; kỳ trân hiếm, đa số hoa thảo chỉ để xem chơi không dùng được cho tu tiên. Nghi là hoa viên của chủ nhân cấm địa.","theLucLienQuan":[],"nguon":["@c0194"]},{"id":"tang-thu-hai-son-mach-suong-mu","name":"Tầng thứ hai (sơn mạch sương mù)","capDo":"khac","parentId":"khu-trung-tam-huyet-sac-thi-luyen","blurb":"Sơn mạch lớn quanh năm bị sương mù dày bao phủ, có sơn động, thung lũng, thạch ốc, thạch điện, thiên địa linh dược và yêu thú thủ hộ.","detail":"Tầng thứ hai chứa thượng phẩm linh dược thật sự hữu dụng, trong đó có ba vị chủ dược luyện Trúc Cơ đan. Sương mù dày khiến người tu tiên bình thường đi vài bước là lạc, phải sờ soạng dò từng bước. Trong sơn mạch có vô số yêu thú như Hỏa diễm thử, Truy phong thỏ, Kim quang mãng, Băng hỏa lang, phần lớn làm thủ hộ thú bảo vệ linh dược.","theLucLienQuan":[],"nguon":["@c0194"]},{"id":"tang-thu-ba-bao-thap","name":"Tầng thứ ba (bảo tháp)","capDo":"khac","parentId":"khu-trung-tam-huyet-sac-thi-luyen","blurb":"Trung tâm cấm địa có tòa bảo tháp gần 100 trượng, quanh là đá lớn và rừng rậm xanh biếc; nghi là nơi ở của chủ nhân cấm địa.","detail":"Tầng thứ ba thần bí nhất, ngăn với tầng hai bởi cấm chế cường đại mà đệ tử Luyện khí kỳ không khai phá được, còn tu sĩ Trúc Cơ kỳ lại không được vào cấm địa, nên bên trong bảo tháp có gì vẫn là bí ẩn.","theLucLienQuan":[],"nguon":["@c0194"]},{"id":"ngon-nui-cam-dia-dai-son","name":"Ngọn núi cấm địa (đại sơn)","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen-khu","blurb":"Ngọn núi cao ngàn trượng trong cấm địa, quanh núi bao phủ sương mù dày đặc phải nhờ Nguyệt dương bảo châu xua tan; trong núi có yêu thú, hai sườn kéo dài liên miên nguy hiểm.","detail":"Núi cao ngàn trượng, cao ngất trong mây không thấy đỉnh, đầy quái thạch gờ đá và cây đại thụ nhiều người ôm; hai sườn núi kéo dài không dứt, địa thế nguy hiểm. Tiếng yêu thú gầm nhẹ vọng ra từ trong núi. Quanh núi bao phủ sương mù trắng dày đặc che lấp bầu trời, không nhìn rõ dù chỉ cách một trượng; trước khi có Nguyệt dương bảo châu không ai dám tới gần. Sau khi sương tan, các tu sĩ ẩn nấp đồng loạt lao vào đại sơn theo các hướng khác nhau.","theLucLienQuan":[],"nguon":["@c0195"]},{"id":"thong-dao-loi-vao-len-nui","name":"Thông đạo (lối vào lên núi)","cn":"","capDo":"khac","parentId":"ngon-nui-cam-dia-dai-son","blurb":"Con đường nhỏ duy nhất an toàn tiến vào ngọn núi cấm địa, khu vực lối vào nhiều sương mù với bụi rậm hoang thảo có thể giấu mười mấy người.","detail":"Con đường nhỏ duy nhất an toàn để tiến vào ngọn núi, gần chỗ Hàn Lập ẩn nấp. Khu vực lối vào nhiều sương mù, bụi rậm hoang thảo rậm rạp có thể ẩn giấu mười mấy người. Hàn Lập ẩn trong bụi rậm nơi đây, chờ Nguyệt dương bảo châu xua tan sương mù rồi mới quan sát các tu sĩ khác lên núi.","theLucLienQuan":[],"nguon":["@c0195"]},{"id":"cam-dia-nui-lua","name":"Cấm địa núi lửa","cn":"","capDo":"khac","parentId":null,"blurb":"Cấm địa miệng núi lửa nơi Hàn Lập và các đệ tử tiến vào thí luyện, đầy yêu thú các cấp.","detail":"Cấm địa núi lửa là khu vực Hàn Lập cùng đệ tử các phái tiến vào thí luyện. Khu vực ngoài chủ yếu có yêu thú cấp thấp, càng vào giữa miệng núi lửa càng có yêu thú cấp trung cao. Vì nguy hiểm nhiều nên tin tức về nơi có linh dược trong tư liệu lại rất ít.","theLucLienQuan":["Hoàng Phong Cốc","Thanh Hư môn","Yểm Nguyệt tông"],"nguon":["@c0196"]},{"id":"son-dong-tu-hau-hoa","name":"Sơn động sản sinh Tử Hầu hoa","cn":"","capDo":"khac","parentId":"cam-dia-nui-lua","blurb":"Sơn động bí mật nơi Hàn Lập chạy đến; trăm năm trước bị hái, nay còn cây con Tử Hầu hoa.","detail":"Một sơn động bí mật trong cấm địa núi lửa sản sinh Tử Hầu hoa. Trăm năm trước nơi đây đã bị hái sạch, nay chỉ còn cây con chưa trưởng thành mà người khác coi vô dụng — chính là mục tiêu trong kế hoạch hái dược của Hàn Lập.","theLucLienQuan":[],"nguon":["@c0196"]},{"id":"loi-vao-cho-pha-cam","name":"Lối vào chỗ phá cấm","cn":"","capDo":"khac","parentId":"cam-dia-nui-lua","blurb":"Nơi người giữ cửa bảy đại phái đứng chờ ngoài cấm địa để theo dõi cuộc đánh cược.","detail":"Lối vào chỗ phá cấm là nơi bảy vị cao thủ Kết Đan kỳ giữ cửa của các phái đứng chờ ngoài cấm địa, trong đó có Lý sư tổ của Hoàng Phong cốc, Phù Vân Tử của Thanh Hư môn và Nghê Thường tiên tử của Yểm Nguyệt tông, cùng theo dõi kết quả cuộc đánh cược thí luyện.","theLucLienQuan":["Thất đại phái"],"nguon":["@c0196"]},{"id":"bi-dong-tu-hau-hoa","name":"Bí động (sơn động chứa Tử Hầu hoa)","cn":"","capDo":"khac","parentId":"cam-dia-nui-lua","blurb":"Sơn động tự nhiên chứa Tử Hầu hoa, do một con rết yêu thú canh giữ.","detail":"Động khẩu cao mấy trượng do tự nhiên tạo thành, đá núi màu xanh nhạt không dấu đục đẽo, nhìn từ ngoài bình thường như các sơn động hoang dã. Thông đạo hẹp dài, kết thúc là một sảnh đá thiên nhiên với vách chung nhũ lấp lánh và khối đá tím mọc Tử Hầu hoa. Đây cũng là sào huyệt của con rết yêu thú bậc trung bảo vệ linh dược.","theLucLienQuan":[],"nguon":["@c0197"]},{"id":"son-coc-dong-nam-tranh-tu-hau-hoa","name":"Sơn cốc đông nam (tranh Tử Hầu hoa tím)","cn":"","capDo":"khac","parentId":"khu-trung-tam-huyet-sac-thi-luyen","blurb":"Sơn cốc u tĩnh phía đông nam vị trí Hàn Lập, nơi ba tu sĩ giằng co tranh hai đóa Tử Hầu hoa tím bên cạnh xác Chích giác lộc.","detail":"Sơn cốc u tĩnh cách Hàn Lập về phía đông nam, nơi thanh niên áo lam, lão giả áo xanh và trung niên đạo sĩ đứng hình tam giác kiêng kị nhau, tranh đoạt hai đóa Tử Hầu hoa tím thành thục; bên cạnh có xác Chích giác lộc thân chia đôi.","theLucLienQuan":["Thiên khuyết bảo","Thanh Hư môn"],"nguon":["@c0198"]},{"id":"thach-oc-tren-dinh-nui","name":"Thạch ốc trên đỉnh núi","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi diễn ra trận đoạt linh thảo giữa phe họ Trần và phe Chung Ngô.","detail":"Thạch ốc trên đỉnh núi, nơi bốn người chia hai phe tranh đoạt linh thảo; Trần thất muội sau đó lấy cớ hái thuốc đi vào thạch ốc, đại ca có kế sách đi theo.","theLucLienQuan":["Trần thị gia tộc","Hóa Đao ổ","Linh thú sơn"],"nguon":["@c0199"]},{"id":"rung-ram-nu-ao-luc","name":"Rừng rậm (cô gái áo lục)","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi cô gái áo lục điều khiển tiểu điêu trắng đấu quái xà hai đầu cạnh cây đại thụ đỏ.","detail":"Khu rừng rậm có cây đại thụ đỏ như lửa mang vài trái đỏ to bằng nắm đấm; cô gái áo lục điều khiển tiểu điêu trắng gian nan đấu con quái xà hai đầu.","theLucLienQuan":[],"nguon":["@c0199"]},{"id":"son-dong-hep-dai-duoi-dat","name":"Sơn động hẹp dài dưới đất","cn":"","capDo":"khac","parentId":null,"blurb":"Sơn động hẹp dài dưới đất nơi đệ tử Yểm Nguyệt tông đi qua.","detail":"Sơn động hẹp và dài dưới đất, nơi khoảng 15-16 đệ tử Yểm Nguyệt tông sống sót áo trắng lặng lẽ đi tới, dẫn đầu là cô gái trẻ Hàn Lập từng thấy xa xa.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0199"]},{"id":"dam-nuoc-xanh-biec-bich-thuy-ngac","name":"Đầm nước xanh biếc (sào huyệt Bích Thủy ngạc)","cn":"","capDo":"khac","parentId":"cam-dia-nui-lua","blurb":"Đầm sâu màu xanh biếc, giữa có đá ngầm đen, dưới có bí quật sâu vài chục trượng — sào huyệt Bích Thủy ngạc chứa nhiều linh dược.","detail":"Một đầm nước xanh biếc trong cấm địa, giữa đầm có vài khối đá ngầm đen, phía dưới là bí quật sâu vài chục trượng. Đây là sào huyệt của yêu thú đỉnh cấp Bích Thủy ngạc (con từng nuốt chết một đệ tử Yểm Nguyệt tông), chứa nhiều linh dược. Đoàn Yểm Nguyệt tông đã dẫn dụ và diệt Bích Thủy ngạc tại đây.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0200"]},{"id":"thach-dien-nho-gan-dinh-nui","name":"Thạch điện nhỏ gần đỉnh núi","cn":"","capDo":"khac","parentId":"cam-dia-nui-lua","blurb":"Tòa thạch điện nhỏ gần đỉnh núi trồng linh dược kỳ thảo, có Thiên Linh quả và Liệt Dương hoa; nơi diễn ra cuộc chiến cô gái áo lục và hán tử Cự Kiếm môn.","detail":"Tòa thạch điện nhỏ nằm gần đỉnh núi trong cấm địa, trồng nhiều linh dược kỳ thảo, trong đó có Thiên Linh quả (chưa thành thục — mục tiêu Hàn Lập cần nhất) và Liệt Dương hoa. Trước thạch điện có khoảng đất trống nơi hán tử Cự Kiếm môn áp bức cô gái áo lục Linh Thú sơn để tranh linh dược.","theLucLienQuan":["Cự kiếm môn","Linh thú sơn"],"nguon":["@c0200"]},{"id":"thach-phong-linh-duoc-vu-si","name":"Thạch phòng chứa linh dược","capDo":"khac","parentId":null,"blurb":"Căn phòng đá chứa số linh dược mà Vũ Si treo làm phần thưởng nếu Hàn Lập thắng trận.","detail":"Trong trận khiêu chiến, Vũ Si tuyên bố nếu Hàn Lập thắng thì sẽ tha cô gái áo lục và cho toàn bộ linh dược trong thạch phòng làm phần thưởng.","theLucLienQuan":[],"nguon":["@c0201"]},{"id":"son-dong-thien-nhien-xoa-tri-nho","name":"Sơn động thiên nhiên (xóa trí nhớ)","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Động thiên nhiên trên đỉnh núi phụ cận nơi Hàn Lập đưa Hạm Vân Chi tới để thi triển Vô ưu châm pháp.","detail":"Một sơn động thiên nhiên gần đỉnh núi trong cấm địa Huyết sắc thí luyện. Hàn Lập ôm Hạm Vân Chi đang hôn mê tới đây, hồi phục thể lực rồi thi triển Vô ưu châm pháp kết hợp Vong Trần hoàn để xóa trí nhớ nửa ngày của nàng. Sau đó hắn nấp sau đại thụ ngoài động quan sát cho tới khi nàng tỉnh dậy rời đi.","theLucLienQuan":["Linh thú sơn"],"nguon":["@c0203"]},{"id":"thach-oc-linh-duoc-dinh-nui","name":"Thạch ốc (chứa linh dược trên đỉnh núi)","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Nhà đá chứa linh dược trên đỉnh núi mà Hàn Lập thu hết, riêng chừa mấy đóa Liệt Dương hoa cho Hạm Vân Chi.","detail":"Thạch ốc là căn nhà đá trên đỉnh núi trong cấm địa, bên trong chứa nhiều linh dược trong đó có Liệt Dương hoa. Hàn Lập vào thu hết linh dược sau khi đánh hôn mê Hạm Vân Chi.","theLucLienQuan":[],"nguon":["@c0203"]},{"id":"thach-dien-co-trong-cam-dia","name":"Thạch điện cổ (trong cấm địa)","cn":"","capDo":"khac","parentId":"khu-vuc-trung-tam-huyet-sac-thi-luyen","blurb":"Tòa thạch điện cổ kính lớn giữa vùng lòng chảo bị quái thạch vây quanh, cửa vào rất nhỏ, bề mặt có thanh quang và bị thi cấm chế mạnh.","detail":"Nằm giữa một vùng lòng chảo bốn phía bị quái thạch cao lớn hình thù kỳ lạ vây quanh, mưa gió không vào. Thạch điện cổ kính lớn nhưng cửa vào chỉ đủ hai người; bề mặt ngẫu nhiên có thanh quang lờ mờ lưu động do bị thi cấm chế mạnh — cấm chế bài xích cả thần thức tu sĩ Kết đan kỳ. Bên trong qua hành lang uốn lượn tới một đại sảnh trống không có lan can ngọc thạch, bên dưới là địa đạo dẫn xuống thế giới đầm lầy.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0204"]},{"id":"the-gioi-dam-lay-duoi-dia-dao","name":"Thế giới đầm lầy (dưới địa đạo)","cn":"","capDo":"khac","parentId":"thach-dien-co-trong-cam-dia","blurb":"Thế giới đầm lầy kỳ dị dưới lòng đất cả trăm mét, cao khoảng ba mươi trượng, rộng vài dặm, bùn đen sủi bọt, giữa treo hộp vàng bảo vật.","detail":"Cuối thông đạo địa đạo là một thế giới đầm lầy kỳ dị, cao khoảng ba mươi trượng, rộng vài dặm, khắp nơi bùn đen sủi bọt; gió nóng sinh ra từ trên khoảng không đầm lầy tạo thế cân bằng đối lưu. Bốn phía biên đầm lầy có kỳ hoa linh thảo cùng mấy loại thiên địa linh dược. Trung gian có tiểu đình bạch ngọc treo lơ lửng một hộp vàng phi phàm. Trong đầm lầy còn ẩn nấp Hắc lân mãng — cự mãng đã nuốt mười mấy đệ tử các phái.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0204"]},{"id":"dia-dao-duoi-lan-can-thach-dien","name":"Địa đạo dưới lan can","cn":"","capDo":"khac","parentId":"thach-dien-co-trong-cam-dia","blurb":"Thông đạo bằng đá dưới lan can ngọc thạch giữa đại sảnh thạch điện, có mấy trăm bậc thang đi xuống với gió nóng khốc liệt.","detail":"Nằm dưới lan can ngọc thạch ở trung ương đại sảnh thạch điện: một địa đạo tối đen có bậc thang đi xuống, không ngừng có gió nóng thổi ra. Thông đạo bằng đá ban đầu chỉ đủ một người, sau vài trăm bậc rộng ra, gió nóng càng khốc liệt; đi xuống gần cả trăm mét thì chấm dứt, dẫn tới thế giới đầm lầy.","theLucLienQuan":[],"nguon":["@c0204"]},{"id":"vung-long-chao-thach-dien","name":"Vùng lòng chảo (quanh thạch điện)","cn":"","capDo":"khac","parentId":"khu-vuc-trung-tam-huyet-sac-thi-luyen","blurb":"Vùng lòng chảo bốn phía bị quái thạch cao lớn hình thù kỳ lạ vây quanh, mưa gió không vào, chính giữa là tòa thạch điện cổ.","detail":"Bốn phía bị quái thạch cao lớn hình thù kỳ lạ vây quanh nên mưa gió không lọt vào; chính giữa vùng lòng chảo là tòa thạch điện cổ. Quanh đó không có dấu vết người tới, khiến Hàn Lập thấy cổ quái dù tư liệu do Chung Ngô đưa cho.","theLucLienQuan":[],"nguon":["@c0204"]},{"id":"thong-dao-da-dia-dao-chien-truong","name":"Thông đạo đá / địa đạo (dưới lòng đất)","cn":"","capDo":"khac","parentId":null,"blurb":"Đường ra vào khu vực chiến đấu hơn mười trượng dưới lòng đất, bị Tiểu ngũ hành phù phong bế.","detail":"Thông đạo đá hơn mười trượng dưới lòng đất là đường ra vào khu vực chiến đấu với Mặc Giao. Khi Tiểu ngũ hành phù phát động, hai bên thông đạo đá ép lại kín mít phong bế lối ra. Bên ngoài thông đạo là đại sảnh thạch điện nơi đệ tử Yểm Nguyệt tông tụ họp.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0206"]},{"id":"the-gioi-duoi-long-dat-khong-gian-dia-ha","name":"Thế giới dưới lòng đất (không gian địa hạ)","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian dưới lòng đất nơi diễn ra trận chiến giết Mặc Giao.","detail":"Không gian dưới lòng đất nơi Hàn Lập cùng cô gái hợp lực giết Mặc Giao; được kim quang chiếu sáng trong khoảnh khắc khi kim chuyên hạ xuống.","theLucLienQuan":[],"nguon":["@c0207"]},{"id":"tuyet-dia-cam-che-bach-ngoc-dinh","name":"Tuyệt địa cấm chế (bạch ngọc đình)","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập và nữ tử tỉnh dậy; có bạch ngọc đình, hộp vàng và linh dược.","detail":"Tuyệt địa có cấm chế phong bế, nơi Hàn Lập và nữ tử tỉnh dậy sau cơn hôn mê. Có bạch ngọc đình, phía trước đặt hộp vàng, xung quanh mọc hơn mười gốc linh dược. Muốn rời khỏi phải hai người hợp lực phá cấm mới ra được.","theLucLienQuan":[],"nguon":["@c0208"]},{"id":"cam-dia-thong-dao-cua-vao","name":"Cấm địa (thông đạo cửa vào)","cn":"","capDo":"khac","parentId":"cam-dia-huyet-sac-thi-luyen","blurb":"Khu vực cửa vào cấm địa nơi bảy tu sĩ Kết đan kỳ phá cấm đón người ra.","detail":"Chiều ngày thứ năm từ khi vào cấm địa, bảy tu sĩ Kết đan kỳ công kích mở cửa vào; lần phá cấm dễ hơn năm ngày trước và thông đạo giữ vững không biến mất sau khi thu pháp bảo, nối thẳng vào cấm địa; đệ tử các phái lần lượt ra, thông đạo sắp đóng khi chỉ còn một canh giờ.","theLucLienQuan":["Yểm Nguyệt tông","Hoàng phong cốc","Linh thú sơn","Cự kiếm môn"],"nguon":["@c0209"]},{"id":"dam-lay-trong-long-dat","name":"Đầm lầy trong lòng đất","cn":"","capDo":"khac","parentId":"the-gioi-dam-lay-duoi-dia-dao","blurb":"Nơi Hàn Lập và Nam Cung Uyển bị cấm chế, từ đây đánh thông đường hầm nối lên mặt đất.","detail":"Hai người dùng Chu tước hoàn và Kim quang chuyên phù bảo đánh thông một đường hầm từ đầm lầy lòng đất nối lên mặt đất; mỗi khi Hàn Lập hết pháp lực Nam Cung Uyển lại truyền sang, tiêu hao hai ba chục năm công lực.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0209"]},{"id":"cam-dia-yem-nguyet","name":"Cấm địa","capDo":"khac","parentId":null,"blurb":"Nơi các phái vừa vào tìm linh dược; sau khi kết thúc các đội lục tục rời đi.","detail":"Khu vực các phái Hoàng phong cốc, Yểm Nguyệt tông, Thanh Hư môn, Linh thú sơn vào tìm linh dược. Sau khi phân định thắng thua đánh cuộc, các đội lần lượt cáo từ rời đi; Lý sư tổ ngửa đầu nhìn im lặng.","theLucLienQuan":["Hoàng Phong Cốc","Yểm Nguyệt tông","Thanh Hư môn","Linh thú sơn"],"nguon":["@c0211"]},{"id":"nghi-su-dien-hoang-phong-coc","name":"Nghị sự điện","capDo":"khac","parentId":null,"blurb":"Điện nghị sự trong Hoàng phong cốc, nơi Lý Hóa Nguyên dẫn hai quản sự vào sau khi trở về cốc.","detail":"Nơi bàn việc trong Hoàng phong cốc; sau khi đoàn cưỡi Ngân giáp giác mãng bay mấy ngày về tới cốc, Lý Hóa Nguyên liền dẫn hai gã quản sự tiến vào để xử lý công việc.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0212","@c0218","@c0219"]},{"id":"bach-thao-vien-hoang-phong-coc","name":"Bách thảo viên","aliases":["Bách dược viên"],"capDo":"khac","parentId":null,"blurb":"Khu vườn dược trong Hoàng phong cốc, có nhà cỏ nơi Mã sư bá cư ngụ và cuối chương giao lại cho Hàn Lập trông coi.","detail":"Vườn trồng linh dược của Hoàng phong cốc, bên trong có một gian nhà cỏ nơi Mã sư bá ở và coi sóc; kết chương, Mã sư bá cáo từ và trả lại quyền trông nom Bách dược viên cho Hàn Lập.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0212"]},{"id":"bach-duoc-vien-hoang-phong-coc","name":"Bách dược viên","capDo":"khac","parentId":"hoang-phong-coc","blurb":"Nơi Hàn Lập cư trú và trồng linh dược, chuẩn bị luyện đan.","detail":"Khu vườn dược trong Hoàng Phong Cốc nơi Hàn Lập ở. Sau chuyến cấm địa, hắn về đây nghỉ ngơi, an bài trồng ba vị chủ dược và chuẩn bị suốt ba năm cho việc luyện Trúc cơ đan.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0213","@c0217"]},{"id":"nhac-loc-dien-hoang-phong-coc","name":"Nhạc lộc điện","capDo":"khac","parentId":"hoang-phong-coc","blurb":"Điện có địa hỏa dùng để luyện khí, luyện đan; có Truyền tống trận và thạch phòng địa hỏa.","detail":"Điện trong Hoàng Phong Cốc chứa địa hỏa phục vụ luyện khí và luyện đan. Nơi đây có Truyền tống trận do tu sĩ Trúc cơ kỳ bảo hộ và các thạch phòng địa hỏa. Hàn Lập đến đây mượn một gian địa hỏa hỏa lực ổn định để luyện Trúc cơ đan.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0213"]},{"id":"dia-hoa-chi-oc","name":"Địa Hỏa Chi Ốc","cn":"","capDo":"khac","parentId":null,"blurb":"Khu luyện đan luyện khí bằng ổ thạch của bổn môn, nơi địa hỏa thịnh vượng.","detail":"Khu vực luyện đan luyện khí của bổn môn, gồm thông đạo ổ thạch, một đại sảnh hình tròn siêu lớn bằng ổ thạch (đường kính bốn năm mươi trượng, cao hơn mười trượng) và ba mươi sáu gian địa hỏa quây quanh. Phía dưới đại sảnh là nơi địa hỏa thịnh vượng nhất; ổ thạch chịu nhiệt cao, không sợ đặc tính cổ quái của địa hỏa nên các tổ sư dùng để xây dựng.","theLucLienQuan":["Bổn môn (tông môn của Hàn Lập)"],"nguon":["@c0214"]},{"id":"gian-muoi-chin-dia-hoa-chi-oc","name":"Gian mười chín (phòng luyện đan)","cn":"","capDo":"khac","parentId":"dia-hoa-chi-oc","blurb":"Phòng luyện đan Hàn Lập được cấp trong Địa Hỏa Chi Ốc.","detail":"Phòng luyện đan vuông vắn cỡ bảy tám trượng, giữa có bếp lò hình tròn bằng ổ thạch cao nửa thước, hai sườn khảm tám đầu rồng đỏ rực làm địa hỏa khẩu, cạnh có bồ đoàn xanh biếc, trên vách treo các hồ lô hỏa tinh. Khi đóng cửa, phòng phong bế tuyệt với ngoại giới trừ khi vài tu sĩ Kết đan kỳ hợp lực mới vào được.","theLucLienQuan":["Bổn môn (tông môn của Hàn Lập)"],"nguon":["@c0214"]},{"id":"cac-nuoc-phia-cuc-tay","name":"Các nước phía cực tây","cn":"","capDo":"khac","parentId":null,"blurb":"Các nước phía cực tây, nơi các sư tổ đem ổ thạch về.","detail":"Các quốc gia ở phía cực tây, nơi sinh ra ổ thạch; các sư tổ phải đem về từ đây vì Việt quốc không sinh ra ổ thạch, việc vận chuyển rất phiền toái.","theLucLienQuan":[],"nguon":["@c0214"]},{"id":"phong-dia-hoa","name":"Phòng địa hỏa","capDo":"khac","parentId":null,"blurb":"Khu vực luyện đan/luyện khí có địa hỏa, đóng bằng mười tám tấm cửa đá phát bạch quang.","detail":"Nơi cung cấp địa hỏa cho đệ tử tông môn luyện đan, thu phí sử dụng và do một đại hán quản lý. Hàn Lập thuê nơi đây gần một năm để luyện Trúc cơ đan rồi bế quan trùng quan Trúc Cơ ngay bên trong, cửa đá đóng chặt bằng bạch quang cho tới khi hắn xuất quan.","theLucLienQuan":[],"nguon":["@c0215","@c0216"]},{"id":"bach-co-duong-hoang-phong-coc","name":"Bách cơ đường","cn":"","capDo":"khac","parentId":"hoang-phong-coc","blurb":"Nơi Chung chưởng môn đang nghị sự khi Hàn Lập tới Nghị sự điện.","detail":"Một nơi nghị sự trong Hoàng Phong Cốc; khi Hàn Lập tới Nghị sự điện thì Chung Linh Đạo còn đang họp bàn ở Bách cơ đường chưa về.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0218"]},{"id":"ky-lan-cac-hoang-phong-coc","name":"Kỳ lân các","capDo":"khac","parentId":"bon-mon-han-lap-dia-hoa","blurb":"Một trong các chỗ trọng yếu nhất của Hoàng phong cốc, chuyên nuôi dưỡng và thuần hóa linh thú.","detail":"Nơi Hoàng phong cốc nuôi dưỡng và thuần hóa linh thú (yêu thú bị thuần phục), phần lớn là linh thú cấp một, vài con cấp hai là của người khác gửi. Hàn Lập đến đây thuê Song đồng thử để hỗ trợ tìm nơi lập động phủ.","theLucLienQuan":["Hoàng phong cốc"],"nguon":["@c0219"]},{"id":"nghenh-khach-dai-ky-lan-cac","name":"Nghênh khách đài","capDo":"khac","parentId":"ky-lan-cac-hoang-phong-coc","blurb":"Tòa tiểu sơn xanh biếc của Kỳ lân các, nơi đệ tử ra tiếp đón khách đến thuê linh thú.","detail":"Tòa tiểu sơn xanh biếc thuộc Kỳ lân các, là nơi một nữ đệ tử trẻ trực để tiếp đón khách thuê linh thú, trong đó có Hàn Lập.","theLucLienQuan":["Hoàng phong cốc"],"nguon":["@c0219"]},{"id":"linh-nhan-chi-tuyen","name":"Linh nhãn chi tuyền","cn":"","capDo":"khac","parentId":null,"blurb":"Nguồn suối phun nước trong động nham thạch, nước ẩn linh khí nồng, một dạng linh nhãn thực thể hóa hiếm thấy.","detail":"Linh nhãn chi tuyền là nguồn suối nhỏ phun nước không ngừng nằm giữa một động nham thạch lớn hơn mười trượng ở phía Tây Bắc Thái nhạc sơn mạch. Linh khí ẩn trong nước, đường vào khéo léo qua khe hở vách núi cao hơn trăm trượng. Đây là một dạng linh nhãn thực thể hóa hiếm thấy thế gian, hình thành khi linh khí quá nồng và duy trì hơn vạn tới mười vạn năm; nó phát linh khí nồng hơn nhiều, tăng tốc tu luyện gần hai ba thành và có thể dùng để di chuyển pháp lực mà không hao tổn công hiệu. Hàn Lập phát hiện nơi này và định khai mở động phủ tại đây.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0220"]},{"id":"linh-thu-son-ky-lan-cac","name":"Linh thú sơn (Kỳ lân các)","cn":"","capDo":"khac","parentId":"ky-lan-cac-hoang-phong-coc","blurb":"Núi của Kỳ lân các chia thành nhiều khu cấm chế nuôi gần ngàn con linh thú.","detail":"Linh thú sơn do Kỳ lân các quản lý, được các cấm chế trận pháp đủ màu chia thành nhiều khối phong bế, mỗi khối tuần dưỡng một loại linh thú; toàn sơn nuôi gần ngàn con. Nghênh khách đài trên núi là nơi tiếp khách và cho thuê linh thú; chỉ đệ tử Kỳ lân các được vào các khu nuôi thú.","theLucLienQuan":["Kỳ lân các","Hoàng phong cốc"],"nguon":["@c0220"]},{"id":"khe-chau","name":"Khê châu","cn":"","capDo":"chau","parentId":"viet-quoc","blurb":"Châu quận nhỏ nhất của Việt quốc, hơn ba phần tư sa mạc, không đại phái trú chân.","detail":"Khê châu là châu quận nhỏ nhất của Việt quốc, hơn ba phần tư diện tích là sa mạc, dân số chỉ hơn vạn người. Do nghèo vật lực nhân lực, không đại phái nào trong thất đại phái trú chân tại đây. Khê châu giáp Kiến châu ở hướng tây, cách nơi Hàn Lập chọn khai mở động phủ hai trăm dặm về hướng tây.","theLucLienQuan":[],"nguon":["@c0220"]},{"id":"kien-chau","name":"Kiến châu","cn":"","capDo":"chau","parentId":"viet-quoc","blurb":"Châu của Việt quốc giáp Khê châu ở hướng tây.","detail":"Kiến châu là một châu của Việt quốc, nằm giáp Khê châu về hướng tây, được nhắc đến khi định vị vị trí nơi Hàn Lập chọn khai mở động phủ.","theLucLienQuan":[],"nguon":["@c0220"]},{"id":"nguyen-vu-quoc","name":"Nguyên Vũ Quốc","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia diện tích trung bình nằm về phương bắc, tu chân giới hai phái chánh tà cân bằng, là nơi đặt Thiên Tinh Tông.","detail":"Nguyên Vũ Quốc là một quốc gia diện tích trung bình, tương đương Việt quốc; không bằng một phần ba Thiên La Quốc và Phong Đô quốc nhưng lớn hơn Khương Quốc và Sát Vân Quốc. Tu chân giới của nước này có hai phái chánh tà cân bằng nhau, trong đó Thiên Tinh Tông là hạch tâm chính phái. Nước này nằm về phương bắc so với động phủ của Hàn Lập, là đích đến của hắn khi đi đổi trận kỳ trận bàn.","theLucLienQuan":["Thiên Tinh Tông"],"nguon":["@c0221"]},{"id":"phuong-thi-thien-tinh-tong","name":"Phường thị Thiên Tinh Tông (Tinh Trần Các)","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Chợ tu tiên bố trí hình vòng tròn của Thiên Tinh Tông, trung tâm là tòa Tinh Trần Các, quanh phường có cấm pháp cấm phi hành.","detail":"Phường thị Thiên Tinh Tông là chợ tu tiên bố trí hình vòng tròn, to hơn phường thị Hoàng Phong Cốc ba phần. Giữa trung tâm là tòa nhà cao hai ba mươi trượng mang ba chữ bạc Tinh Trần Các — cửa hàng chính của tông môn — trong khi các tòa xung quanh chỉ cao bằng một phần mười. Quanh phường thị có cấm pháp cấm phi hành buộc tu sĩ hạ xuống đất. Bên trong có các gian luyện khí, gian chế phù và một Linh thú viện thuần dưỡng yêu thú kể cả thượng cấp làm hộ viện linh thú.","theLucLienQuan":["Thiên Tinh Tông"],"nguon":["@c0221","@c0359"]},{"id":"linh-tuyen-nham-dong","name":"Linh tuyền nham động (động phủ Hàn Lập)","capDo":"khac","parentId":"viet-quoc","blurb":"Nham động chứa linh nhãn chi tuyền được Hàn Lập cải tạo thành động phủ mật thất gồm mười ba phòng và một đại sảnh, kèm dược viên bí mật.","detail":"Linh tuyền nham động là nham động ẩn chứa một linh nhãn chi tuyền nhất cấp mà Hàn Lập tình cờ tìm được ở phụ cận đỉnh núi. Hắn dùng ngân kiếm và kim nhận mở rộng, hình thành động phủ sơ bộ gồm mười ba căn phòng lớn nhỏ và một đại sảnh trên mặt đất, bố trí tiểu mê tung trận che dấu toàn bộ lối ra vào và lập một dược viên bí mật gần đó. Nơi đây trở thành mật thất luyện công bí mật giúp hắn tăng tốc tu luyện.","theLucLienQuan":[],"nguon":["@c0221"]},{"id":"phuong-thi-nho-tieu-dieu","name":"Phường thị nhỏ (tiêu điều)","capDo":"khac","parentId":null,"blurb":"Phường thị tiêu điều Hàn Lập ghé, chỉ khoảng ba mươi người tu tiên bên ngoài, phần lớn tập trung về phía Tinh Trần Các ở giữa.","detail":"Một phường thị nhỏ và tiêu điều, số người tu tiên bên ngoài chỉ khoảng ba mươi người. Phần lớn người đều đi về phía Tinh Trần Các nằm ở giữa phường thị. Trong phường thị có gian hàng luyện khí của Từ lão giả với chiêu bài cam kết luyện khí thất bại trả lại bằng linh thạch.","theLucLienQuan":["Từ gia"],"nguon":["@c0222"]},{"id":"tinh-tran-cac","name":"Tinh Trần Các","capDo":"khac","parentId":"phuong-thi-nho-tieu-dieu","blurb":"Cửa hàng ở giữa phường thị, nơi phần lớn người tu tiên đi tới; Hàn Lập cho rằng đây là nơi có loại trận kỳ, trận bàn tốt nhất.","detail":"Cửa hàng nằm ở giữa phường thị nhỏ, thu hút phần lớn người tu tiên tới. Hàn Lập nhắm tới đây vì cho rằng chỉ Tinh Trần Các mới có loại trận kỳ, trận bàn tốt nhất mà hắn cần mua nhiều.","theLucLienQuan":["Thiên Tinh Tông"],"nguon":["@c0222"]},{"id":"gian-hang-luyen-khi-tu-lao-gia","name":"Gian hàng luyện khí của Từ lão giả","capDo":"khac","parentId":"phuong-thi-nho-tieu-dieu","blurb":"Cửa tiệm nhỏ trong phường thị gồm ba gian phòng và một hậu viện, có chiêu bài cam kết luyện khí thất bại trả lại bằng linh thạch.","detail":"Gian hàng luyện khí của Từ lão giả trong phường thị nhỏ, quy mô khiêm tốn với ba gian phòng và một hậu viện. Nổi bật với chiêu bài khẩu khí lớn cam kết nếu luyện khí thất bại sẽ trả lại bằng linh thạch, cùng lời quảng cáo có thể luyện chế đỉnh cấp pháp khí. Đây là nơi Hàn Lập ghé vào vì hiếu kỳ và thỏa thuận giao tài liệu để Từ lão giả luyện chế.","theLucLienQuan":["Từ gia"],"nguon":["@c0222"]},{"id":"bi-diem-dai-sanh-ngam","name":"Bí điếm (đại sảnh ngầm)","cn":"","capDo":"khac","parentId":"phuong-thi-thien-tinh-tong","blurb":"Đại sảnh hình tròn đường kính khoảng mười trượng dưới lòng đất, xa hoa như nhà đại phú, nơi tổ chức cạnh mại hội của bí điếm.","detail":"Vào qua địa đạo dài mười trượng từ một gian hàng nhỏ cách phường thị một dặm; đại sảnh trải thảm đỏ tươi, tường ngọc bích trắng, treo đèn lồng đỏ, có bảy tám ghế dài cho khách và bàn cùng ghế gỗ cho ba người chủ trì đối diện.","theLucLienQuan":["Bí điếm (cạnh mại hội)"],"nguon":["@c0223"]},{"id":"vung-dat-cuc-tay","name":"Vùng đất cực tây","cn":"","capDo":"vuc","parentId":null,"blurb":"Khu vực nơi khôi lỗi cơ quan thuật lưu hành cực kỳ rộng rãi.","detail":"Vùng đất cực tây là khu vực nơi khôi lỗi cơ quan thuật lưu hành cực kỳ rộng rãi, có tông phái Thiên Trúc giáo lấy đạo pháp này khai môn lập phái. Được nhắc tới trong lời giới thiệu cặp khôi lỗi cơ quan thú tại phiên đấu giá bí điếm.","theLucLienQuan":["Thiên Trúc giáo"],"nguon":["@c0224"]},{"id":"dai-sanh-dau-gia-bi-diem","name":"Đại sảnh đấu giá (bí điếm)","cn":"","capDo":"khac","parentId":"bi-diem-dai-sanh-ngam","blurb":"Sảnh đấu giá của bí điếm với cửa đá đóng mở kiểm soát ra vào, có ghế đàn mộc cho ba người định giá.","detail":"Đại sảnh diễn ra buổi đấu giá kín của bí điếm. Cửa đá đóng mở kiểm soát việc ra vào — khách bị giữ lại tới khi giao dịch chấm dứt mới được mở cửa ra ngoài. Bên trong có ghế đàn mộc dành cho ba người mang mặt nạ định giá vật phẩm. Nơi diễn ra việc rao bán thiết tinh thượng phẩm, đôi khôi lỗi thú và gốc Hoàng Tinh chi ngàn năm.","theLucLienQuan":["Bí điếm (cạnh mại hội)"],"nguon":["@c0225"]},{"id":"cua-hieu-luyen-khi-lao-gia-toc-bac","name":"Cửa hiệu Luyện khí (của lão giả tóc bạc)","cn":"","capDo":"khac","parentId":null,"blurb":"Cửa hiệu nơi Hàn Lập nhận mối làm ăn, bán vỏ ngô công làm tài liệu luyện khí.","detail":"Cửa hiệu Luyện khí do một lão giả tóc bạc làm chủ kiêm Luyện khí sư. Hàn Lập tới đây bán vỏ cứng ngô công làm tài liệu luyện khí; lão giả hớn hở mời trà nhưng thái độ nóng nảy khiến Hàn Lập hoài nghi có phải mình tìm nhầm Luyện khí sư.","theLucLienQuan":[],"nguon":["@c0227"]},{"id":"thanh-thi-co-cua-hieu-luyen-khi-cam-bay","name":"Thành thị có cửa hiệu luyện khí (phạm vi cấm bay)","cn":"","capDo":"thanh","parentId":null,"blurb":"Thành thị nơi Hàn Lập giao tài liệu Mặc Giao cho Từ lão; trong thành có quy định cấm bay, ra khỏi phạm vi mới được dùng pháp khí phi hành.","detail":"Đô thị có cửa hiệu luyện khí của Từ lão. Nội thành áp quy định cấm bay nên Hàn Lập phải ra khỏi phạm vi cấm bay mới phóng Thần Phong Châu bay lên không trung lên đường về động phủ.","theLucLienQuan":[],"nguon":["@c0228"]},{"id":"khu-rung-mai-phuc-tran-chien-khoi-loi","name":"Khu rừng mai phục / trận chiến khôi lỗi","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng đất dưới đường bay của Hàn Lập, nơi bốn năm tu sĩ Trúc Cơ Hậu Kỳ bị gần trăm khôi lỗi từ trong rừng vây công liên tục.","detail":"Khu rừng nằm dưới lộ trình bay về động phủ của Hàn Lập. Từ trong rừng đám khôi lỗi (hổ báo, cung thủ, cận chiến) được bổ sung liên tục duy trì số lượng bất biến để vây công nhóm Trúc Cơ Hậu Kỳ tu sĩ; một siêu cấp quang trụ đường kính mấy trượng cũng bắn ra từ trong rừng.","theLucLienQuan":[],"nguon":["@c0228"]},{"id":"khu-rung-cu-ho-vay-khon","name":"Khu rừng (chiến trường vây khốn Cự Hổ)","cn":"","capDo":"khac","parentId":null,"blurb":"Khu rừng nơi diễn ra trận nam tử khôi vũ dùng Cự Hổ vây khốn và diệt khẩu đám tu sĩ Nguyên Vũ Quốc.","detail":"Nơi diễn ra trận vây khốn: Cự Hổ vọt ra từ rìa rừng, đám tu sĩ bị khốn trong hộ trạo, còn Hàn Lập ẩn trong tầng mây xám cách mặt đất trăm mấy trượng quan sát toàn cảnh.","theLucLienQuan":["Thiên Trúc Giáo","Nguyên Vũ Quốc (tu tiên giới / các gia môn)"],"nguon":["@c0229"]},{"id":"go-dat-nho-tran-khoi-loi","name":"Gò đất nhỏ","capDo":"khac","parentId":null,"blurb":"Gò đất nhỏ nơi Lâm sư huynh ẩn nấp, bị vũ khí khôi lỗi của Hoàng Long chỉ về trước khi lộ diện.","detail":"Gò đất nhỏ đằng xa nơi Lâm sư huynh cải trang quái nhân túi vải bố ẩn nấp theo dõi cuộc đối đầu. Vũ khí của các khôi lỗi do Hoàng Long điều khiển đồng loạt hướng về gò đất này, khiến Hàn Lập nhận ra còn người thứ ba nấp ở đó trước khi Lâm sư huynh lộ diện.","theLucLienQuan":[],"nguon":["@c0230"]},{"id":"dong-phu-han-lap","name":"Động phủ Hàn Lập","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập ở, được bao bọc bởi Điên Đảo Ngũ Hành trận trải hơn mười mẫu; bị Thiên Trúc giáo công kích và là nơi Lâm sư huynh chạy trốn rồi chết.","detail":"Động phủ của Hàn Lập, quanh nó hắn bố trí Điên Đảo Ngũ Hành trận phủ hơn mười mẫu, từ ngoài nhìn không có gì khác thường. Tại đây Thiên Trúc giáo kéo tới tấn công đại trận đòi giao người, và Lâm sư huynh đã chạy chết trong phạm vi trận, gần cửa động.","theLucLienQuan":["Thiên Trúc giáo"],"nguon":["@c0231"]},{"id":"noi-cuc-tay","name":"Nơi cực tây","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng đặt Cổ Độc tông, nơi phát nguồn cổ độc khiến Lâm sư huynh chết.","detail":"Vùng đất ở nơi cực tây, nơi Cổ Độc tông đặt tông môn và là nguồn gốc của loại cổ độc mà Lâm sư huynh trúng phải.","theLucLienQuan":["Cổ Độc tông"],"nguon":["@c0233"]},{"id":"tru-tang-that-dong-phu-han-lap","name":"Trữ tàng thất (động phủ Hàn Lập)","capDo":"khac","parentId":"dong-phu-han-lap","blurb":"Phòng cất chứa của Hàn Lập, bố trí kết giới đặc thù giữ dược tính linh dược không mất.","detail":"Phòng cất chứa trong động phủ Hàn Lập, bố trí kết giới đặc thù giữ dược tính linh dược vĩnh viễn không tiêu tán; nơi cất hai gốc dược tài lâu năm và các bí mật Hàn Lập lo sợ bị thần thức Lôi Vạn Hạc phát hiện.","theLucLienQuan":[],"nguon":["@c0234"]},{"id":"luc-ba-dong","name":"Lục Ba động","capDo":"khac","parentId":"thai-nhac-son-mach","blurb":"Động phủ của Lý Hóa Nguyên, nằm sau một thác nước lớn dưới ngọn núi ở phía đông Thái Nhạc sơn mạch, non xanh nước biếc, cực kỳ bí mật.","detail":"Chỗ non xanh nước biếc phía đông Thái Nhạc sơn mạch, động phủ xây sau màn nước của một thác nước lớn dưới ngọn núi. Bên trong có một tiểu cốc thiên nhiên hoa thơm chim hót, cây xanh nước sạch, nuôi các động vật nhỏ quý hiếm là bảo bối của sư nương. Trong đại sảnh, Hàn Lập tham kiến Lý Hóa Nguyên cùng sư nương. Vị trí do Lôi Vạn Hạc chỉ.","theLucLienQuan":["Sư môn Lý Hóa Nguyên"],"nguon":["@c0237"]},{"id":"luan-kiem-duong-luc-ba-dong","name":"Luận Kiếm đường","capDo":"khac","parentId":"luc-ba-dong","blurb":"Gian nhà đá phụ cận cực kỳ rộng lớn trong Lục Ba động, nơi Hàn Lập gặp Tứ sư huynh Tống Mông.","detail":"Một gian nhà đá rộng lớn nằm trong Lục Ba động — động phủ của Lý Hóa Nguyên. Trong lúc Vu Khôn dẫn Hàn Lập tham quan, hai người ghé Luận Kiếm đường và gặp Tống Mông đang có mặt tại đây.","theLucLienQuan":["Môn hạ Lý Hóa Nguyên"],"nguon":["@c0238"]},{"id":"tang-thu-that-ly-hoa-nguyen","name":"Tàng thư thất (của Lý Hóa Nguyên)","capDo":"khac","parentId":"dong-phu-han-lap","blurb":"Thạch thất thấp bé cách đại sảnh không xa, được kết giới màu hỏa hồng bảo vệ, chứa kho công pháp của Lý Hóa Nguyên.","detail":"Một thạch thất bình thường, thấp bé, nằm cách đại sảnh động phủ Lý Hóa Nguyên không xa, được một tầng kết giới màu hỏa hồng bảo vệ khiến người ngoài không vào được. Bên trong chứa kho công pháp năm sáu mươi kiện của lão. Lý Hóa Nguyên vươn ngón tay vạch mở một cửa rộng khoảng một trượng để hai người sánh vai bước qua.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0239"]},{"id":"linh-thu-son","name":"Linh thú sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm Hàn Lập đoán Hạm Vân Chi vẫn còn ở đó. Nơi này chỉ được nhắc qua hồi tưởng khi hắn nhìn Kim trúc bút.","detail":"Linh thú sơn xuất hiện như nơi gắn với Hạm Vân Chi trong ký ức của Hàn Lập. Chương này chưa miêu tả trực tiếp địa hình hay sự kiện tại đây.","theLucLienQuan":["Linh thú sơn"],"nguon":["@c0242"]},{"id":"khu-cho-ban-mon","name":"Khu chợ bản môn","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập tới để sưu tầm nguyên liệu luyện đan và mầm linh thảo. Đây là một nguồn cung cho kế hoạch luyện đan, chế phù của hắn.","detail":"Trước khi bế quan, Hàn Lập chạy tới khu chợ trong môn phái để tìm các nguyên liệu cần cho hai phương thuốc cổ và cây con linh thảo. Tại đây cùng các khu chợ khác, hắn may mắn thu được một loại nguyên liệu của Luyện khí tán.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0242"]},{"id":"khu-cho-thien-tinh-tong","name":"Khu chợ Thiên tinh tông","cn":"","capDo":"khac","parentId":null,"blurb":"Khu chợ Hàn Lập lui tới để tìm nguyên liệu luyện đan và mầm linh thảo. Nó bổ sung nguồn cung ngoài khu chợ bản môn.","detail":"Hàn Lập đến khu chợ Thiên tinh tông trong giai đoạn chuẩn bị bế quan. Mục tiêu của hắn là gom nguyên liệu luyện đan và mầm linh thảo để dùng bình nhỏ thần bí thúc sinh trưởng.","theLucLienQuan":["Thiên tinh tông"],"nguon":["@c0242"]},{"id":"dong-phu-cua-han-lap","name":"Động phủ của Hàn Lập","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập bế quan bốn năm và tự xây dựng hệ thống luyện đan, luyện phù, trồng dược bí mật.","detail":"Trong động phủ này, Hàn Lập mở vườn thuốc bí mật, bố trí lỗ lấy ánh sáng cho bình nhỏ thu nạp linh khí, luyện Luyện khí tán, chế phù và cất giữ các túi trữ vật trước khi rời đến Lục Ba động.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0243"]},{"id":"vuon-thuoc-bi-mat-trong-dong-phu","name":"Vườn thuốc bí mật trong động phủ","cn":"","capDo":"khac","parentId":"dong-phu-cua-han-lap","blurb":"Vườn thuốc nhỏ Hàn Lập bí mật mở bên trong động phủ để thúc sinh linh dược.","detail":"Vườn thuốc này được bố trí lỗ nhỏ trên vách đá để ánh mặt trời chiếu vào và giúp bình nhỏ thu nạp linh khí. Đại trận che phủ động phủ bảo vệ khu vực, khiến Hàn Lập không lo bị người ngoài phát hiện.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0243"]},{"id":"vuon-thuoc-lon-ben-ngoai","name":"Vườn thuốc lớn bên ngoài","cn":"","capDo":"khac","parentId":"dong-phu-cua-han-lap","blurb":"Vườn thuốc bên ngoài động phủ được Hàn Lập dùng làm lớp che mắt.","detail":"Trái với vườn thuốc bí mật thật sự bên trong động phủ, vườn thuốc lớn bên ngoài được Hàn Lập cố ý bố trí để đánh lạc hướng người khác về việc trồng và thúc sinh linh dược.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0243"]},{"id":"dai-sanh-tiep-khach-luc-ba-dong","name":"Đại sảnh tiếp khách ở Lục Ba động","cn":"","capDo":"khac","parentId":"luc-ba-dong","blurb":"Nơi Hàn Lập được dẫn vào gặp vợ chồng Lý Hóa Nguyên, Hồng Phất, Tống Mông và thiếu nữ áo hồng.","detail":"Sau khi Vũ Huyễn mở cấm chế, Hàn Lập được dẫn vào đại sảnh tiếp khách. Tại đây Lý Hóa Nguyên bảo hắn bái kiến Hồng Phất và để bà xem xét hắn.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0243"]},{"id":"dong-phu-cua-ly-hoa-nguyen","name":"Động phủ của Lý Hóa Nguyên","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Động phủ của Lý Hóa Nguyên là nơi Hồng Phất đưa đồ đệ đến xem xét Hàn Lập và nơi vợ chồng Lý Hóa Nguyên báo chuyện song tu cho hắn.","detail":"Tại động phủ này, Hồng Phất sau khi quan sát Hàn Lập đã rời đi cùng nữ đồ đệ, còn Lý Hóa Nguyên và phu nhân ở lại giải thích ý định kết bạn song tu. Cuối chương, Tống Mông và Vũ Huyễn bị cho rời khỏi phòng khách để Hàn Lập tiếp tục bị hỏi về lời đồn liên quan Đổng Huyên Nhi.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0244"]},{"id":"yen-gia-dia-ban","name":"Yến gia","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Điểm đến của Hàn Lập và Đổng Huyên Nhi trong chuyến viễn hành. Đây là nơi Yến gia tổ chức Đoạt bảo đại hội.","detail":"Yến gia là địa điểm tổ chức Đoạt bảo đại hội, nơi các đệ tử của cao thủ Kết Đan kỳ mấy nước lân cận được mời đến tranh tài và kết giao. Trong chương này, Hàn Lập và Đổng Huyên Nhi rời Lục Ba động để lên đường đến đó.","theLucLienQuan":["Yến gia"],"nguon":["@c0245"]},{"id":"viet-quoc-tu-tien-gioi","name":"Việt quốc tu tiên giới","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Không gian tu tiên nơi Yến gia được xưng là đệ nhất gia tộc. Các thế lực và tu sĩ Kết Đan kỳ trong vùng đều bị cuốn vào mạng lưới kết giao quanh Đoạt bảo đại hội.","detail":"Việt quốc tu tiên giới là bối cảnh rộng của sự kiện Yến gia tổ chức Đoạt bảo đại hội. Chương này cũng cho biết gần đây trong giới tu tiên có dấu hiệu bất ổn, đến cả tu sĩ Trúc Cơ kỳ cũng có người gặp chuyện.","theLucLienQuan":["Yến gia","Hoàng Phong Cốc"],"nguon":["@c0245"]},{"id":"yen-luong-son","name":"Yến Lương sơn","cn":"","aliases":[],"capDo":"khac","parentId":"viet-quoc","blurb":"Ngọn núi có phong cảnh không tệ, nơi đặt Yến Linh bảo của Yến gia.","detail":"Yến Lương sơn là khu vực đặt trọng địa Yến Linh bảo. Đây là bối cảnh dẫn vào Đoạt bảo đại hội của Yến gia.","theLucLienQuan":["Yến gia"],"nguon":["@c0246"]},{"id":"yen-linh-bao","name":"Yến Linh bảo","cn":"","aliases":["Yến linh bảo"],"capDo":"khac","parentId":"yen-luong-son","blurb":"Trọng địa của Yến gia và địa điểm tổ chức Đoạt bảo đại hội.","detail":"Yến Linh bảo nằm trong Yến Lương sơn, là nơi được ghi trên thư mời Đoạt bảo đại hội mà Hàn Lập cầm trong tay. Đây là điểm đến của Hàn Lập và Đổng Huyên Nhi sau khi rời Lục Ba động.","theLucLienQuan":["Yến gia"],"nguon":["@c0246","@c0282","@c0363"]},{"id":"nhan-linh-son","name":"Nhạn Linh sơn","cn":"","aliases":[],"capDo":"khac","parentId":"viet-quoc","blurb":"Khu vực Hàn Lập và Đổng Huyên Nhi tìm tới theo vị trí trên thư mời.","detail":"Tại Nhạn Linh sơn, hai người chờ người Yến gia tới tiếp đón nhưng không thấy ai xuất hiện. Sự vắng mặt này khiến Hàn Lập cảnh giác và chuẩn bị rời đi nếu tiếp tục không có hồi đáp.","theLucLienQuan":["Yến gia"],"nguon":["@c0246"]},{"id":"dinh-nui-noi-don-khach","name":"Đỉnh núi nơi đón khách","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Đỉnh núi nơi đón khách là nơi Hàn Lập và Đổng Huyên Nhi chờ người Yến gia tới tiếp dẫn. Sự chậm trễ tại đây liên quan trực tiếp tới việc nhóm lục bào đánh bị thương đệ tử tiếp khách.","detail":"Tại đỉnh núi này, Hàn Lập và Đổng Huyên Nhi thấy hai con Song thủ vụ chở Yến Vũ cùng Yến Linh bay tới. Huynh muội Yến gia xin lỗi vì để khách chờ lâu, rồi dẫn hai người về Yến Linh bảo.","theLucLienQuan":["Yến gia"],"nguon":["@c0247"]},{"id":"khoang-giua-hai-ngon-nui-nho","name":"Khoảng giữa hai ngọn núi nhỏ","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Khoảng giữa hai ngọn núi nhỏ là vị trí cấm chế che giấu Yến Linh bảo. Khi Yến Vũ dùng lệnh bài mở cấm chế, cổ bảo hùng vĩ mới hiện ra giữa lưng chừng núi.","detail":"Bên ngoài nhìn vào, nơi này chỉ là khoảng không trống rỗng. Sau khi lệnh bài phát ánh sáng vàng, hào quang ngũ sắc hiện ra rồi tan đi, để lộ tòa cổ bảo của Yến gia.","theLucLienQuan":["Yến gia"],"nguon":["@c0247"]},{"id":"vo-truong-trong-yen-linh-bao","name":"Võ trường trong Yến Linh bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Võ trường trong Yến Linh bảo là nơi diễn ra cuộc đối峙 giữa đại hán Yến gia và quái nhân lục bào. Khu vực tỷ thí được bao quanh bởi màn hào quang trắng, bên ngoài có hai nhóm người quan chiến.","detail":"Khi Hàn Lập và Đổng Huyên Nhi từ ngoài nhìn vào Yến Linh bảo, họ thấy hai tu sĩ lơ lửng trong màn hào quang trắng trên võ trường. Một bên là đệ tử Yến gia, bên kia là quái nhân thuộc nhóm lục bào; xung quanh có đệ tử Yến gia và nhóm lục bào theo dõi.","theLucLienQuan":["Yến gia","Nhóm lục bào tóc vàng mắt xám"],"nguon":["@c0247"]},{"id":"duong-da-trong-yen-linh-bao","name":"Đường đá trong Yến linh bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Tuyến đường Hàn Lập đi qua khi tự mình quan sát Yến linh bảo. Hai bên có các cửa hàng phục vụ nhu cầu tu tiên cơ bản.","detail":"Đường đá trong Yến linh bảo là nơi Hàn Lập vừa đi vừa nhìn thấy các cửa hàng bán phù lục, luyện khí, nguyên liệu luyện đan và pháp khí cấp thấp. Đây cũng là tuyến dẫn hắn tới khu vực trà lâu trước khi tình cờ gặp lại Mặc Thải Hoàn.","theLucLienQuan":["Yến gia"],"nguon":["@c0250"]},{"id":"tra-lau-trong-yen-linh-bao","name":"Trà lâu trong Yến linh bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Điểm đến ban đầu của Hàn Lập khi muốn tìm tu sĩ đồng cấp để kết giao. Hắn cho rằng tu sĩ thường thích dừng chân uống trà tại nơi này.","detail":"Trà lâu trong Yến linh bảo được Hàn Lập xem là nơi có thể gặp các tu sĩ cùng cấp, thuận tiện trao đổi kinh nghiệm và mở rộng quan hệ. Kế hoạch tới trà lâu bị ngắt quãng khi hắn đi ngang cửa hàng và gặp lại Mặc Thải Hoàn.","theLucLienQuan":["Yến gia"],"nguon":["@c0250"]},{"id":"tieu-diem-cua-me-con-nghiem-thi-trong-yen-linh-bao","name":"Tiểu điếm của mẹ con Nghiêm thị trong Yến linh bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Tiểu điếm nhỏ trong Yến linh bảo là nơi Nghiêm thị và Mặc Thải Hoàn buôn bán phù lục cấp thấp, nguyên liệu rẻ để kiếm linh thạch mua thuốc. Đây cũng là nơi Hàn Lập gặp lại Nghiêm thị sau gần mười năm.","detail":"Cửa hàng chỉ rộng chừng sáu bảy trượng, có quầy gỗ bày một ít phù lục cấp thấp và nguyên liệu rẻ tiền. Sau khi Yến Trụ chết, mẹ con Nghiêm thị dựa vào nơi này sinh sống; gần đây nguồn cung phù lục bị cắt vì một tu sĩ muốn ép nạp Mặc Thải Hoàn làm thiếp.","theLucLienQuan":["Yến linh bảo"],"nguon":["@c0251"]},{"id":"lam-chau","name":"Lam châu","cn":"","capDo":"chau","parentId":null,"blurb":"Lam châu là khu vực từng xảy ra biến động quyền lực sau cái chết của Âu Dương Phi Thiên. Kinh Giao hội và Ngũ sắc môn tranh đoạt lợi ích tại đây, dẫn đến Mặc phủ bị cuốn vào tai họa.","detail":"Theo lời Nghiêm thị, sau khi Âu Dương Phi Thiên chết, cục diện Lam châu chuyển biến mạnh. Kinh Giao hội từng chiếm hơn nửa lợi ích nhưng bị Ngũ sắc môn đánh bại, sau đó Mặc phủ cũng bị tập kích và tan rã.","theLucLienQuan":["Kinh Giao hội","Ngũ sắc môn","Độc phách sơn trang","Mặc phủ"],"nguon":["@c0251"]},{"id":"yen-linh","name":"Yến linh","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực Hàn Lập còn lưu lại vài ngày sau các sự kiện ở Yến gia. Mẹ con Nghiêm thị đang sống tại đây và chịu áp lực từ tu sĩ Yến gia.","detail":"Yến linh là nơi Mặc gia tạm cư, đồng thời là bối cảnh Hàn Lập ra mặt xử lý tu sĩ Yến gia quấy nhiễu mẹ con Nghiêm thị. Sau khi chia tay Mặc Thải Hoàn, Hàn Lập vẫn ở trong khu vực này và đến trà lâu Thiên hạc cư để tìm tu sĩ Trúc Cơ.","theLucLienQuan":["Yến gia","Mặc phủ"],"nguon":["@c0252"]},{"id":"thien-hac-cu","name":"Thiên hạc cư","cn":"","capDo":"khac","parentId":"yen-linh","blurb":"Trà lâu ba tầng có kiến trúc cổ kính tại Yến linh. Hàn Lập cảm nhận nơi đây có nhiều dao động pháp lực, trong đó có tu sĩ Trúc Cơ kỳ.","detail":"Sau khi rời Mặc Thải Hoàn, Hàn Lập đến Thiên hạc cư. Hắn bỏ qua tầng dưới có phàm nhân và tu sĩ Luyện khí kỳ, rồi hướng lên tầng ba vì cảm nhận được dao động pháp lực của các tu sĩ Trúc Cơ, thậm chí có người mạnh hơn mình.","theLucLienQuan":["Yến gia"],"nguon":["@c0252"]},{"id":"lau-ba-tra-lau-yen-gia","name":"Lầu ba trà lâu Yến gia","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Nơi Hàn Lập gặp nhóm tu sĩ Trúc Cơ kỳ của thất đại phái và quan sát cục diện giằng co với nhóm tu sĩ nước ngoài.","detail":"Lầu ba trà lâu Yến gia tập trung các tu sĩ Trúc Cơ kỳ trong thời gian đại hội đoạt bảo. Tại đây Hàn Lập nhập bàn nhóm thất đại phái, nghe bàn về Càn Khôn tháp phù bảo, tu sĩ nước ngoài và lai lịch Quỷ Linh Môn.","theLucLienQuan":["Yến gia","Thất đại phái","Quỷ Linh Môn"],"nguon":["@c0253"]},{"id":"thien-la-quoc","name":"Thiên La quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia của sáu tông phái ma đạo, trong đó có Quỷ Linh Môn.","detail":"Thiên La quốc được Vô Du Tử nhắc là nơi đặt căn cơ của sáu tông phái ma đạo. Việc Quỷ Linh Môn từ Thiên La quốc xuất hiện ở Yến Linh bảo khiến nhóm thất đại phái Việt quốc lo ngại về mục đích thật sự của họ.","theLucLienQuan":["Ma đạo lục tông Thiên La quốc","Quỷ Linh Môn"],"nguon":["@c0253"]},{"id":"khuong-quoc","name":"Khương quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Một trong hai nước nằm giữa Thiên La quốc và Việt quốc trong suy luận của Hàn Lập.","detail":"Khương quốc được Hàn Lập nhắc tới khi loại trừ khả năng ma đạo Thiên La quốc trực tiếp xâm lấn Việt quốc. Sự tồn tại của nước này cùng Xa Kỵ quốc làm khoảng đệm địa lý giữa hai bên.","theLucLienQuan":[],"nguon":["@c0253"]},{"id":"xa-ky-quoc","name":"Xa Kỵ quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Nước nhỏ nằm giữa Thiên La quốc và Việt quốc, được Hàn Lập dùng làm căn cứ suy luận về nguy cơ xâm lấn.","detail":"Xa Kỵ quốc cùng Khương quốc nằm giữa Thiên La quốc và Việt quốc. Theo suy xét của Hàn Lập, tu tiên giới của hai nước này không yếu, khiến giả thuyết ma đạo âm thầm vượt qua để xâm lấn Việt quốc trở nên khó hợp lý.","theLucLienQuan":[],"nguon":["@c0253"]},{"id":"xu-thien-tich","name":"Xử thiên tích","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Địa điểm được trung niên họ Vũ đề xuất để nhóm tu sĩ ngày mai tiếp tục gặp mặt. Nơi này dự kiến dùng cho luận đạo và giao dịch vài vật phẩm nhỏ.","detail":"Sau buổi trao đổi kinh nghiệm tu luyện, trung niên họ Vũ đề nghị mọi người cùng tới Xử thiên tích vào ngày hôm sau. Hàn Lập và những người khác đều đồng ý với đề nghị này.","theLucLienQuan":[],"nguon":["@c0254"]},{"id":"phong-nguyet-khach-diem","name":"Phong nguyệt khách điếm","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Khách điếm ở đông nam Yến linh bảo chuyên tiếp đãi tu sĩ bên ngoài. Hàn Lập chọn nơi này vì thanh tĩnh, ít người và gần tường thành.","detail":"Phong nguyệt khách điếm nằm ở khu vực tương đối vắng vẻ của Yến linh bảo, sát tường thành nên thuận lợi cho việc rút lui nếu có biến. Hàn Lập theo bản đồ tìm đến và quyết định trú lại tại đây để giảm phiền toái.","theLucLienQuan":["Yến gia"],"nguon":["@c0254"]},{"id":"phi-van-cac","name":"Phi vân các","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Kiến trúc cao nhất trong Yến linh bảo, nơi Yến gia lão tổ tiếp nhận bẩm báo và tiếp Thiếu chủ Quỷ linh môn. Bên trong có khu vực canh phòng nghiêm ngặt và mật thất dùng cho mật đàm.","detail":"Ban đêm, Yến gia lão tổ ở trong Phi vân các cùng các lão giả áo xám, sau đó nghe bẩm báo về việc Thiếu chủ Quỷ linh môn đã đến. Cuộc gặp ngoài đại sảnh dẫn tới việc lão tổ đưa Thiếu chủ vào mật thất có cấm chế mạnh để nói chuyện suốt đêm.","theLucLienQuan":["Yến gia","Quỷ linh môn"],"nguon":["@c0254"]},{"id":"phong-do-quoc","name":"Phong Đô quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia được nhắc qua chính đạo liên minh mà Huyền Dạ đặt câu hỏi trong mật hội Yến gia. Nó liên quan đến thế cục phản ứng của chính đạo trước việc Khương quốc và Xa Kỵ quốc thất thủ.","detail":"Trong lúc chất vấn các điểm then chốt, Huyền Dạ hỏi nếu Khương quốc và Xa Kỵ quốc thật sự bị ma đạo lục tông chiếm lĩnh thì chính đạo liên minh của Phong Đô quốc hiện đang làm gì. Địa danh này mở rộng bối cảnh chiến sự ra ngoài Việt quốc, Khương quốc và Xa Kỵ quốc.","theLucLienQuan":["Chính đạo liên minh Phong Đô quốc"],"nguon":["@c0255"]},{"id":"thien-nam-khu","name":"Thiên Nam khu","cn":"","capDo":"vuc","parentId":null,"blurb":"Thiên Nam khu là phạm vi rộng được nhắc tới trong tham vọng bá nghiệp của Quỷ linh môn. Việc lợi dụng Huyết linh đại pháp và liên kết với Yến gia được đặt trong viễn cảnh tranh bá ở khu vực này.","detail":"Yến gia lão tổ cho rằng nếu Huyết linh đại pháp thành tựu nhờ Yến Như Yên và Thiếu chủ Quỷ linh môn, Quỷ linh môn có thể mưu đồ bá nghiệp không chỉ trong ma đạo lục tông mà còn ở Thiên Nam khu. Đây là bối cảnh rộng của biến động chính-ma đang lan ra nhiều nước.","theLucLienQuan":["Quỷ linh môn","Ma đạo lục tông Thiên La quốc","Yến gia"],"nguon":["@c0256"]},{"id":"phong-duyet-khach-diem","name":"Phong Duyệt khách điếm","cn":"","capDo":"khac","parentId":null,"blurb":"Khách điếm nơi Hàn Lập, Đổng Huyên Nhi, Yến Vũ và Phong sư huynh trở về sau khi nam tử diễm lệ rút lui.","detail":"Tại Phong Duyệt khách điếm, Đổng Huyên Nhi kể lại cảm giác bị mê thuật khống chế thân tâm. Hàn Lập cũng tại đây suy luận Mê Tâm thuật của nam tử diễm lệ có thể không hữu hiệu với nam tử.","theLucLienQuan":[],"nguon":["@c0258"]},{"id":"ngon-nui-phia-tay-yen-linh-bao","name":"Ngọn núi phía tây Yến Linh Bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Trường đấu dành cho tu sĩ Việt quốc trong đại hội đoạt bảo. Đây cũng là nơi Quỷ Linh môn bí mật bố trí Âm Hỏa đại trận để vây khốn người dự hội.","detail":"Theo thông báo đại hội đoạt bảo, tu sĩ Việt quốc phải tới ngọn núi phía tây Yến Linh Bảo để tham gia thi đấu. Quỷ Linh môn đã bố trí Âm Hỏa đại trận tại đây, cho người giả làm Yến gia kiểm nhân số và chuẩn bị khởi động kế hoạch phục kích.","theLucLienQuan":["Quỷ Linh môn","Yến gia","Hoàng Phong Cốc","Bảy đại phái Việt quốc"],"nguon":["@c0259"]},{"id":"ngon-nui-phia-dong-yen-linh-bao","name":"Ngọn núi phía đông Yến Linh Bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Trường đấu được thông báo dành cho tu sĩ nước khác trong đại hội đoạt bảo. Việc chia hai ngọn núi tách tu sĩ Việt quốc khỏi tu sĩ ngoại quốc.","detail":"Người thông báo bên ngoài khách điếm cho biết đại hội đoạt bảo chia làm hai tổ. Tu sĩ Việt quốc đến ngọn núi phía tây, còn tu sĩ nước khác đến ngọn núi phía đông; quá giờ sẽ bị tước quyền thi đấu.","theLucLienQuan":["Yến gia"],"nguon":["@c0259"]},{"id":"dia-diem-hoang-phong-coc","name":"Hoàng Phong cốc","cn":"","capDo":"khac","parentId":"thai-nhac-son-mach","blurb":"Địa điểm tông môn trong Thái Nhạc sơn mạch, nơi diễn ra cuộc họp mật của nhiều tu sĩ Kết Đan kỳ. Sau cuộc họp, nơi đây chuyển sang trạng thái động viên khẩn cấp.","detail":"Cách Yến Linh Bảo ngoài ngàn dặm, Hoàng Phong cốc trong Thái Nhạc sơn mạch xuất hiện cảnh nhiều tu sĩ Kết Đan kỳ họp trong mật thất. Sau đó pháp khí bay đầy trời, từng đội tu sĩ rời cốc trong đêm, cho thấy tình thế đã bước vào trạng thái chiến sự.","theLucLienQuan":["Hoàng Phong Cốc","Bảy đại phái Việt quốc"],"nguon":["@c0259"]},{"id":"can-nha-dan-trong-yen-linh-bao","name":"Căn nhà dân trong Yến Linh Bảo","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Nơi nam tử diễm lệ ngồi nghe vài nam nữ thuộc hạ bẩm báo sau khi rời khách điếm. Địa điểm này cho thấy Quỷ Linh môn còn có điểm liên lạc kín trong Yến Linh Bảo.","detail":"Trong một căn nhà dân tại Yến Linh Bảo, nam tử diễm lệ ngồi trên ghế và nghe vài nam nữ cung kính bẩm báo. Cảnh này diễn ra song song với việc Quỷ Linh môn bố trí bẫy ở núi phía tây.","theLucLienQuan":["Quỷ Linh môn"],"nguon":["@c0259"]},{"id":"dai-dat-o-nui-phia-tay","name":"Đài đất ở núi phía tây","cn":"","capDo":"khac","parentId":"ngon-nui-phia-tay-yen-linh-bao","blurb":"Vị trí nhóm giả dạng người Yến gia đứng nghị luận và kiểm nhân số trước khi mở trận. Tại đây Vương Thiền nhận báo cáo còn thiếu hai người và ra lệnh hành động.","detail":"Trên đài đất của trường đấu núi phía tây, nhóm người được tưởng là Yến gia thực ra là tu sĩ Quỷ Linh môn. Sau khi kiểm nhân số, thuộc hạ báo thiếu hai người, khiến Vương Thiền lập tức ra lệnh mở đại trận và phái thập nhị vệ truy sát.","theLucLienQuan":["Quỷ Linh môn","Yến gia"],"nguon":["@c0259"]},{"id":"khu-dai-hoi-doat-bao-tren-nui","name":"Khu đại hội đoạt bảo trên núi","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Khu vực trên núi nơi diễn ra đại hội đoạt bảo và bẫy Âm Hỏa đại trận của Quỷ Linh môn cùng Yến gia. Khách tham dự được gọi tới báo danh rồi bị màn đen của pháp trận bao phủ.","detail":"Đây là không gian chính của biến cố trong chương 260. Người Quỷ Linh môn giả Yến gia hô gọi khách tham dự đại hội, các tu sĩ tụ vào phạm vi trận, rồi Âm Hỏa đại trận khởi động với màn đen bao phủ hơn trăm trượng quanh pháp trận.","theLucLienQuan":["Quỷ Linh môn","Yến gia"],"nguon":["@c0260"]},{"id":"dan-dat-trong-vung-suong-mu","name":"Đàn đất trong vùng sương mù","cn":"","capDo":"khac","parentId":"khu-dai-hoi-doat-bao-tren-nui","blurb":"Vị trí người Quỷ Linh môn giả Yến gia đi ra để hô gọi khách tham dự đại hội tới báo danh. Đây là điểm trung gian trong kế dụ người vào phạm vi cấm chế.","detail":"Sau khi nhận lệnh từ Vương Thiền, tu sĩ Quỷ Linh môn mặc trang phục Yến gia đi ra khỏi vùng sương mù trên đàn đất, đứng cách trận pháp không xa và lớn tiếng gọi mọi khách nhân tới báo danh. Hành động này khiến nhiều tu sĩ, gồm đôi nam nữ Yểm Nguyệt tông, tiến vào phạm vi Âm Hỏa đại trận.","theLucLienQuan":["Quỷ Linh môn","Yến gia"],"nguon":["@c0260"]},{"id":"goc-dai-thu-goc-dong-bac-dai-tran","name":"Gốc đại thụ góc đông bắc đại trận","cn":"","capDo":"khac","parentId":"khu-dai-hoi-doat-bao-tren-nui","blurb":"Nơi một nam một nữ đệ tử Yểm Nguyệt tông đứng riêng tư ngoài phạm vi cấm chế. Sau lời gọi báo danh, cả hai rời vị trí này và tiến vào trận.","detail":"Gốc đại thụ ở góc đông bắc đại trận là một trong các vị trí ban đầu nằm ngoài phạm vi cấm chế của Âm Hỏa đại trận. Đôi nam nữ Yểm Nguyệt tông đứng thân mật tại đây, nhưng sau khi người giả Yến gia gọi báo danh, họ cũng đi vào khu vực bị pháp trận khống chế.","theLucLienQuan":["Yểm Nguyệt tông"],"nguon":["@c0260"]},{"id":"phia-tay-phap-tran","name":"Phía tây pháp trận","cn":"","capDo":"khac","parentId":"khu-dai-hoi-doat-bao-tren-nui","blurb":"Khu vực Hàn Lập đứng quan sát và không chịu đi báo danh. Việc hắn đứng ngoài phạm vi cấm chế khiến Vương Thiền chú ý và đích thân ra tay chặn đường.","detail":"Phía tây pháp trận là nơi Hàn Lập giữ khoảng cách với Âm Hỏa đại trận trong lúc các tu sĩ khác bị dụ tới báo danh. Từ vị trí này, hắn nhận ra sơ hở móng tay xanh biếc của người giả Yến gia, nghi ngờ có bẫy và chuẩn bị dùng Thần Phong Chu thoát thân.","theLucLienQuan":["Hoàng Phong Cốc","Quỷ Linh môn"],"nguon":["@c0260"]},{"id":"huyet-van","name":"Huyết Vân","cn":"","capDo":"khac","parentId":null,"blurb":"Huyết Vân là không gian mây máu do Vương Thiền khống chế trong trận truy sát Hàn Lập. Nó vừa vây khốn, vừa hấp thu mê vụ, vừa được dùng làm phương tiện cho Huyết Độn.","detail":"Trong Huyết Vân, Vương Thiền điều khiển khô lâu phun hắc quang và hao tinh huyết thúc công pháp để ép Hàn Lập lộ thân. Hàn Lập dùng tiểu đao Phù Bảo và phù lục hỏa long đánh tan Huyết Vân mở đường thoát, còn Mạc Giao chi Độc từ mê vụ bị Huyết Vân hấp thu lại trở thành nguyên nhân khiến Vương Thiền trúng độc.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0262"]},{"id":"dinh-nui-mai-phuc","name":"Đỉnh núi mai phục","cn":"","capDo":"khac","parentId":"yen-linh-bao","blurb":"Đỉnh núi mai phục là nơi Quỷ Linh Môn bố trí lực lượng khống chế tu sĩ bảy phái. Sau khi Vương Thiền rời đi, nơi này bị nhóm Hợp Hoan Tông tập kích.","detail":"Quỷ Linh Môn vốn giữ hai nữ tu sĩ bị chế phục tại khu mai phục. Nhóm Hợp Hoan Tông do Điền Bất Khuyết cầm đầu bất ngờ đánh tới và cướp hai người này, khiến Vương Thiền phải ra lệnh báo Yến gia lão tổ rút lui.","theLucLienQuan":["Quỷ Linh Môn","Hợp Hoan Tông","Yến gia"],"nguon":["@c0262"]},{"id":"hoang-son","name":"Hoàng Sơn","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Địa điểm được Hàn Lập hồi tưởng liên quan đến trận chiến nguy hiểm với thiếu chủ Quỷ Linh Môn.","detail":"Hàn Lập nghĩ rằng nếu Thanh Hỏa Chướng không vô tình phát huy công hiệu trong trận trước đó, hắn có thể đã chôn xương ở Hoàng Sơn.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0263"]},{"id":"linh-khoang-dai-hiep-coc","name":"Linh khoáng Đại Hiệp Cốc","cn":"","aliases":["Linh thạch khoáng","linh khoáng nguyên"],"capDo":"khac","parentId":"viet-quoc","blurb":"Mỏ linh thạch trữ lượng khá lớn được bảy phái điều đội Tuyên Nhạc tới tăng cường phòng thủ.","detail":"Linh khoáng nằm trong một hiệp cốc sâu hơn trăm trượng trên hoang nguyên thuộc lãnh nội Việt quốc, vốn có lực lượng thủ vệ cũ rất mỏng do Từ Hưng phụ trách. Trước nguy cơ tiểu đội Ma Đạo tập kích, đội Tuyên Nhạc đến tăng viện, bố trí Tứ Sát Trận và chia nhóm tuần tra.","theLucLienQuan":["Việt quốc Thất Phái","Thiên Khuyết Bảo","Yểm Nguyệt Tông"],"nguon":["@c0263"]},{"id":"hoang-nguyen-trong-lanh-noi-viet-quoc","name":"Hoang nguyên trong lãnh nội Việt Quốc","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Khu hoang nguyên rộng lớn nơi đội chi viện đến sau vài ngày di chuyển.","detail":"Đội tu sĩ của Tuyên Nhạc sau vài ngày đã tới một hoang nguyên rộng lớn trong lãnh nội Việt Quốc, nơi có hiệp cốc che giấu linh thạch khoáng cần tăng cường phòng vệ.","theLucLienQuan":["Việt quốc Thất Phái"],"nguon":["@c0263"]},{"id":"hiep-coc-sau-hon-tram-truong","name":"Hiệp cốc sâu hơn trăm trượng","cn":"","capDo":"khac","parentId":"hoang-nguyen-trong-lanh-noi-viet-quoc","blurb":"Khe núi lớn trong hoang nguyên, nơi đặt linh thạch khoáng và có trận pháp che phủ.","detail":"Hiệp cốc sâu hơn trăm trượng được ảo trận che phủ, bên trong là khu vực linh khoáng và nơi đội chi viện gặp lực lượng thủ vệ cũ do Từ Hưng dẫn đầu.","theLucLienQuan":["Thiên Khuyết Bảo","Yểm Nguyệt Tông"],"nguon":["@c0263"]},{"id":"hoang-nguyen-cach-linh-thach-khoang-gan-tram-dam","name":"Hoang nguyên cách linh thạch khoáng gần trăm dặm","cn":"","capDo":"khac","parentId":null,"blurb":"Khu hoang nguyên nơi Hàn Lập luyện thu hồn thằn lằn bằng khôi lỗi thú. Địa điểm này cách linh thạch khoáng nơi hắn làm nhiệm vụ gần trăm dặm.","detail":"Tại hoang nguyên này, Hàn Lập cho cơ quan thú hình thằn lằn săn thằn lằn thật, rồi tự mình dùng Khiên Hồn Thuật rút hồn phách và thu vào bình ngọc nhỏ. Về sau, nơi đây cũng là khu vực hắn để các khôi lỗi thú cấp thấp càn quét sào huyệt thằn lằn nhằm thu thêm hồn phách phục vụ luyện khôi lỗi cấp hai.","theLucLienQuan":[],"nguon":["@c0264"]},{"id":"viet-quoc","name":"Việt Quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Việt Quốc là địa bàn chính của thất phái và trung tâm chiến sự với Ma Đạo lục tông. Cuộc xâm nhập của Ma Đạo khiến nơi này trở thành chiến trường lớn của khu vực.","detail":"Trong chương này, Việt Quốc bị Ma Đạo lục tông xâm nhập và là nơi Việt Quốc thất phái tổ chức phòng thủ, mai phục, dựa vào đại trận cùng viện quân các nước lân cận để chống lại thế công Ma Đạo.","theLucLienQuan":["Việt Quốc thất phái","Ma Đạo lục tông"],"nguon":["@c0265"]},{"id":"tu-kim-quoc","name":"Tử Kim Quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Tử Kim Quốc là quốc gia lân cận Việt Quốc, phái lực lượng tu tiên đến chi viện trong cuộc chiến chống Ma Đạo. Sự tham gia của nước này góp phần cân bằng chiến cuộc.","detail":"Khi Việt Quốc thất phái lâm nguy, tu sĩ Tử Kim Quốc cùng Nguyên Vũ Quốc và các nước lân cận đến hỗ trợ. Viện quân này khiến Ma Đạo không thể nhanh chóng nuốt trọn Việt Quốc.","theLucLienQuan":["Tử Kim Quốc tu tiên giới","Việt Quốc thất phái"],"nguon":["@c0265","@c0357"]},{"id":"khu-vuc-thien-nam","name":"Khu vực Thiên Nam","cn":"","capDo":"vuc","parentId":null,"blurb":"Khu vực Thiên Nam là vùng lớn nơi Ma Đạo lục tông được xem là một trong hai đại thế lực. Chiến cuộc Việt Quốc là một phần biến động trong cục diện khu vực này.","detail":"Ma Đạo lục tông được nhắc như một trong hai đại thế lực của khu vực Thiên Nam. Việc thế lực này xâm nhập Việt Quốc kéo nhiều quốc gia và tu tiên giới lân cận vào chiến sự.","theLucLienQuan":["Ma Đạo lục tông","Việt Quốc thất phái"],"nguon":["@c0265"]},{"id":"hap-coc-phia-duoi-sat-tran","name":"Hạp cốc phía dưới sát trận","cn":"","capDo":"khac","parentId":"linh-khoang-dai-hiep-coc","blurb":"Hạp cốc phía dưới sát trận là khu vực bên dưới tứ sát trận, nơi nhóm áo hồng Ma Diễm môn và hoàng y tu sĩ Thiên Sát tông tiến tới. Đây trở thành chiến trường chính khi phe ma đạo công kích tuyến phòng thủ thất phái.","detail":"Trong chương này, phe ma đạo triển khai lực lượng dưới khu vực sát trận: Thiên Sát tông phái hoàng y tu sĩ đánh úp bốn sát trận, còn Ma Diễm môn đưa hồng y nhân tới gần để bày trận phóng Thanh dương ma hỏa. Khu vực này gắn trực tiếp với tuyến phòng thủ linh quáng của thất phái.","theLucLienQuan":["Thất đại phái","Ma Diễm môn","Thiên Sát tông"],"nguon":["@c0266"]},{"id":"duong-ham-trong-linh-quang","name":"Đường hầm trong linh quáng","cn":"","capDo":"khac","parentId":"linh-quang","blurb":"Lối thoát bên trong linh quáng, vốn do khai thác một phân mạch linh thạch cũ tạo thành. Đường hầm có thể thông ra ngoài mấy chục dặm nhưng nhanh chóng trở thành hiểm địa khi Tứ sát trận bị phá.","detail":"Dư Hưng tiết lộ thông đạo này trong lúc phe thất đại phái bị Thanh dương ma hỏa ép vào tuyệt cảnh. Hơn năm mươi tu sĩ rút vào đây, dự định hủy động khẩu để trì hoãn ma đạo khai thác linh thạch, nhưng sau đó đường hầm rung chuyển vì tiếng nổ lớn, bùn đất sụp xuống và mọi thứ chìm vào bóng tối.","theLucLienQuan":["Thất đại phái","Ma đạo lục tông"],"nguon":["@c0267"]},{"id":"hang-dong-thien-nhien-tren-vach-da","name":"Hang động thiên nhiên trên vách đá","cn":"","capDo":"khac","parentId":null,"blurb":"Hang động thiên nhiên nơi Hàn Lập thoát ra sau vụ sập đường hầm linh quáng. Đây là điểm xác nhận hắn gặp nạn nhưng sống sót.","detail":"Vài canh giờ sau khi đường hầm sụp lở, khôi lỗi thằn lằn của Hàn Lập phá vách chui ra nơi này để dò xét bốn phía. Hàn Lập theo sau thoát ra, quan sát hoàn cảnh xung quanh với vẻ may mắn.","theLucLienQuan":[],"nguon":["@c0267"]},{"id":"dong-thach-nhu-vo-danh-duoi-long-dat","name":"Động thạch nhũ vô danh dưới lòng đất","cn":"","capDo":"khac","parentId":"linh-khoang-dai-hiep-coc","blurb":"Khu động thạch nhũ thông nhiều ngả dưới lòng đất nơi Hàn Lập thoát ra sau vụ sập đường hầm. Bên trong có nhiều huyệt động nối nhau và có luồng gió dẫn đến nhóm tu sĩ sống sót.","detail":"Sau khi bị chôn dưới đất, Hàn Lập nhờ khôi lỗi thú dò đường và lần theo gió để đi qua các huyệt động trong khu động thạch nhũ. Đây là không gian dẫn tới nhũ động lớn chứa Bạch tri thù, truyền tống trận cổ, hài cốt và lệnh bài màu lam.","theLucLienQuan":["Thất đại phái"],"nguon":["@c0268"]},{"id":"duoc-vien-bi-mat-cua-that-dai-tong-phai","name":"Dược viên bí mật của thất đại tông phái","cn":"","capDo":"khac","parentId":"linh-khoang-dai-hiep-coc","blurb":"Khu dược viên ẩn giấu gần linh quáng của thất đại phái. Sau khi linh quáng bị phá, nơi này cũng bị ma đạo tập kích và hủy hoại.","detail":"Một ngày sau vụ phá linh quáng, dược viên trồng dược thảo được thất đại tông phái ẩn tàng gần đó bị đánh lén. Linh thảo chuẩn bị để luyện đan bị phá hủy hoàn toàn, cây con còn lại cũng bị Thanh dương ma hỏa thiêu sạch.","theLucLienQuan":["Thất đại phái","Ma đạo lục tông"],"nguon":["@c0268"]},{"id":"nhu-dong-chua-bach-tri-thu-va-truyen-tong-tran","name":"Nhũ động chứa Bạch tri thù và truyền tống trận","cn":"","capDo":"khac","parentId":"dong-thach-nhu-vo-danh-duoi-long-dat","blurb":"Huyệt động lớn nơi nhóm Hàn Lập phát hiện Bạch tri thù, xác đệ tử Yểm Nguyệt Tông, truyền tống trận cổ và các lệnh bài màu lam. Cuối chương, cửa động duy nhất bị mạng nhện trắng phong kín.","detail":"Trong nhũ động này, Bạch tri thù đang cắn xé thi thể một đệ tử Yểm Nguyệt Tông. Phía sau nó có quặng linh thạch bao quanh lục giác truyền tống trận cổ, năm hài cốt tỏa ngũ sắc quang hoa và lệnh bài màu lam; sau giao chiến, yêu thú phun chất lỏng trắng hóa thành mạng nhện bít cửa động.","theLucLienQuan":["Thất đại phái","Yểm Nguyệt Tông"],"nguon":["@c0268"]},{"id":"son-dong","name":"Sơn động","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian chiến đấu chật hẹp nơi nhóm tu sĩ đối đầu Bạch tri thù rồi Huyết tri thù. Địa thế hạn chế ngự khí phi hành khiến các tu sĩ bị yêu thú áp đảo bằng tốc độ.","detail":"Trong sơn động, cửa ra bị mạng nhện phong kín, truyền tống trận, hài cốt và lệnh bài vẫn còn là mục tiêu chưa xử lý. Khi Bạch tri thù hóa thành Huyết tri thù, không gian hẹp khiến nhóm tu sĩ khó kéo dài khoảng cách và lần lượt bị giết rất nhanh.","theLucLienQuan":["Thất đại phái","Hóa Đao ổ","Linh Thú Sơn"],"nguon":["@c0269"]},{"id":"truyen-tong-tran-trong-son-dong","name":"Truyền tống trận trong sơn động","cn":"","capDo":"khac","parentId":"son-dong","blurb":"Truyền tống trận nằm trong sơn động cùng hài cốt và lệnh bài. Hàn Lập chú ý đến nó trong lúc Tuyên Nhạc và Lữ Thiên Mông còn đang đối phó Huyết tri thù.","detail":"Truyền tống trận là mục tiêu đáng chú ý còn lại trong động sau khi nhóm tu sĩ phát hiện hài cốt và lệnh bài. Ở chương này, Hàn Lập chỉ quan sát và chưa kịp xử lý vì Huyết tri thù liên tục gây nguy hiểm.","theLucLienQuan":[],"nguon":["@c0269"]},{"id":"dong-khau","name":"Động khẩu","cn":"","capDo":"khac","parentId":"nhu-dong-chua-bach-tri-thu-va-truyen-tong-tran","blurb":"Động khẩu là cửa ra của nhũ động nơi Huyết tri thù nhiều lần tìm cách thoát khỏi thế vây công.","detail":"Trong trận với Hàn Lập, Huyết tri thù nhiều lần hướng về động khẩu để tránh bị tiêu hao, nhưng bị khôi lỗi thú của Hàn Lập bức trở lại khu vực giao chiến.","theLucLienQuan":[],"nguon":["@c0270"]},{"id":"huyet-dong-co-truyen-tong-tran","name":"Huyệt động có Truyền tống trận","cn":"","capDo":"khac","parentId":null,"blurb":"Huyệt động nơi Hàn Lập thu Đại na di lệnh, phát hiện Cổ Truyền tống trận hư hại và lấy trứng nhện yêu thú. Sau đó hắn thiêu hủy dấu vết và phong kín cửa động.","detail":"Trong huyệt động này, Hàn Lập thăm dò hài cốt ngũ sắc, thu Đại na di lệnh, phát hiện một góc Truyền tống trận đã hỏng và sao chép hoa văn vào ngọc giản. Hắn còn lấy hai trứng nhện yêu thú, đốt thi thể Tuyên Nhạc, Lữ Thiên Mông cùng hài cốt ngũ sắc, thu hạt châu nhiều màu rồi dùng Thanh Nguyên kiếm quang phá nát cửa động để che giấu bí mật.","theLucLienQuan":[],"nguon":["@c0271"]},{"id":"dong-thach-nhu","name":"Động thạch nhũ","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực hang động nơi Hàn Lập dựa theo hướng gió để tìm lối ra. Sau vài canh giờ, hắn rời được khỏi địa đạo qua lối bí mật.","detail":"Sau khi phong kín cửa động chứa Truyền tống trận, Hàn Lập men theo hướng gió trong động thạch nhũ để tìm đường ra. Khu vực này nối với địa đạo bí mật giúp hắn thoát khỏi nơi nguy hiểm.","theLucLienQuan":[],"nguon":["@c0271"]},{"id":"thien-nam","name":"Thiên Nam","cn":"","capDo":"vuc","parentId":null,"blurb":"Khu vực tu tiên giới rộng lớn được nhắc khi Hàn Lập suy tính về chiến tranh chính ma. Sách ở Thiên Tri các cũng nói hiện tại trong Thiên Nam hầu như không thấy cổ Truyền tống trận.","detail":"Thiên Nam là phạm vi rộng mà Hàn Lập cân nhắc khi nghĩ đến việc rời Việt quốc. Hắn cho rằng nếu chiến tranh chính ma lan rộng thì Thiên Nam khó có nơi thật sự yên ổn, đồng thời tư liệu ở Thiên Tri các cho biết cổ Truyền tống trận tại Thiên Nam gần như đã thành truyền thuyết.","theLucLienQuan":["Bảy phái Việt quốc","Sáu tông ma đạo"],"nguon":["@c0271"]},{"id":"thien-tri-cac","name":"Thiên Tri các","cn":"","capDo":"khac","parentId":"dia-diem-hoang-phong-coc","blurb":"Nơi Hàn Lập tra cứu tư liệu về Đại na di lệnh và Cổ Truyền tống trận. Tại đây hắn đọc được công dụng của Đại na di lệnh nhưng không tìm được cách sửa cổ trận.","detail":"Sau khi trở về Hoàng Phong cốc, Hàn Lập vào Thiên Tri các đọc Động Huyền giải và biết Đại na di lệnh là pháp khí bảo hộ khi truyền tống siêu khoảng cách. Hắn tiếp tục tra nhiều sách trận pháp để tìm tư liệu sửa Cổ Truyền tống trận nhưng thất bại, rồi nhớ tới một người có thể giúp mình.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0271"]},{"id":"nghi-su-dien","name":"Nghị Sự điện","cn":"","capDo":"khac","parentId":"dia-diem-hoang-phong-coc","blurb":"Địa điểm Hàn Lập được phù truyền âm triệu tập tới. Lệnh tập hợp tại đây báo hiệu nhiệm vụ chiến trường bắt đầu.","detail":"Sau khi Hàn Lập xử lý hai trứng nhện trong động phủ, phù truyền âm yêu cầu hắn nhanh chóng tập hợp tại Nghị Sự điện. Đây là điểm chuyển từ việc chuẩn bị cá nhân sang nhiệm vụ môn phái.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0272"]},{"id":"kim-co-nguyen","name":"Kim Cổ nguyên","cn":"","capDo":"vuc","parentId":null,"blurb":"Chiến trường nằm ở ranh giới Việt quốc và Xa Kỵ quốc. Thất phái và lục tông giao chiến tại đây suốt một năm với cả đại chiến lẫn tiểu chiến.","detail":"Kim Cổ nguyên là nơi Hàn Lập bị giữ lại sau nhiệm vụ hộ tống linh thạch, trở thành lực lượng chiến đấu của thất phái. Trong một năm, hai phe liên tục tiêu hao tu sĩ Trúc Cơ kỳ, còn tu sĩ Kết Đan kỳ thường xuất chiến vào ban đêm.","theLucLienQuan":["Bảy phái Việt quốc","Sáu tông ma đạo"],"nguon":["@c0272"]},{"id":"tran-doanh-cua-that-phai-tai-kim-co-nguyen","name":"Trận doanh của thất phái tại Kim Cổ nguyên","cn":"","capDo":"khac","parentId":"kim-co-nguyen","blurb":"Khu doanh trại của thất phái trên chiến trường Kim Cổ nguyên. Nơi này có mộc ốc, thạch ốc, cấm chế và các phân khu theo môn phái.","detail":"Sau khi rời chiến trường, Hàn Lập dùng Thần Phong chu trở về trận doanh. Doanh trại này là nơi tu sĩ dựng nhà tạm bằng mộc hệ hoặc thổ hệ đạo thuật, đồng thời có khu giao dịch để mua bán chiến lợi phẩm và vật hiếm.","theLucLienQuan":["Bảy phái Việt quốc","Hoàng Phong Cốc"],"nguon":["@c0272"]},{"id":"thach-oc-cua-han-lap","name":"Thạch ốc của Hàn Lập","cn":"","capDo":"khac","parentId":"tran-doanh-cua-that-phai-tai-kim-co-nguyen","blurb":"Chỗ ở tạm của Hàn Lập trong doanh trại Kim Cổ nguyên. Hắn dùng trận kỳ tiểu cấm phong bế nơi này trước khi kiểm kê chiến lợi phẩm.","detail":"Thạch ốc là nơi Hàn Lập trở về sau khi rút khỏi hoang nguyên. Tại đây hắn bố trí cấm chế, lấy túi trữ vật thu được ra phân loại, giữ vật hữu dụng và chuẩn bị đem phần không dùng được đi đổi linh thạch.","theLucLienQuan":["Hoàng Phong Cốc","Bảy phái Việt quốc"],"nguon":["@c0272"]},{"id":"moc-oc-giao-dich-trong-doanh-trai","name":"Mộc ốc giao dịch trong doanh trại","cn":"","capDo":"khac","parentId":"tran-doanh-cua-that-phai-tai-kim-co-nguyen","blurb":"Khu nhà lớn màu vàng trong doanh trại nơi tu sĩ bày quầy giao dịch. Hàn Lập bán chiến lợi phẩm, đổi linh thạch và mua Long Ngâm thảo tại đây.","detail":"Mộc ốc giao dịch là điểm tập trung nhiều vật phẩm hiếm từ chiến trường, gồm dược thảo, công pháp, pháp khí và đan phương. Hàn Lập nhiều lần thu hoạch ở đây, từ dược tài cho Tụ Linh đan đến hai phương thuốc cổ và Long Ngâm thảo.","theLucLienQuan":["Bảy phái Việt quốc"],"nguon":["@c0272"]},{"id":"so-giao-dich","name":"Sở giao dịch","cn":"","capDo":"khac","parentId":"tran-doanh-cua-that-phai-tai-kim-co-nguyen","blurb":"Sở giao dịch là nơi Hàn Lập trao đổi tài nguyên với Trần mập trong doanh trại. Tại đây hắn gặp lại Trần sư muội sau sự kiện cấm địa.","detail":"Ở chương 273, Hàn Lập đến sở giao dịch để hỏi tin tức phương thuốc mới và giao dịch với Trần mập. Khi chuẩn bị rời đi vì chưa có tin mới, hắn gặp Trần sư muội mang túi trữ vật tới giao cho Trần mập.","theLucLienQuan":["Hoàng Phong cốc","Trần thị"],"nguon":["@c0273"]},{"id":"trung-tam-dai-tran","name":"Trung tâm đại trận","cn":"","capDo":"khac","parentId":"tran-doanh-cua-that-phai-tai-kim-co-nguyen","blurb":"Trung tâm đại trận là khu vực trọng yếu trong doanh trại thất phái. Chỗ ở của Lý Hóa Nguyên được đặt tại đây do thân phận tu sĩ Kết Đan kỳ.","detail":"Chương 273 cho biết nhà lớn thoải mái của Lý Hóa Nguyên nằm ở trung tâm đại trận, khác hẳn nơi ở phổ thông. Đây là nơi Hàn Lập tới vấn an sư phụ và gặp các tu sĩ Kết Đan rời phòng.","theLucLienQuan":["Hoàng Phong cốc","Bảy phái Việt quốc"],"nguon":["@c0273"]},{"id":"cho-o-cua-ly-hoa-nguyen","name":"Chỗ ở của Lý Hóa Nguyên","cn":"","capDo":"khac","parentId":"trung-tam-dai-tran","blurb":"Chỗ ở của Lý Hóa Nguyên là căn nhà lớn tại trung tâm đại trận trong doanh trại. Hàn Lập tới đây vấn an sư phụ, gặp Tống Mông và nhóm khách Kết Đan.","detail":"Ở chương 273, Hàn Lập đến chỗ ở của Lý Hóa Nguyên nhưng phải chờ ngoài cửa vì sư phụ đang thương lượng với khách. Tại đây Tống Mông mời hắn luận bàn, rồi bảy tu sĩ Kết Đan rời phòng, trong đó có Nam Cung Uyển.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0273"]},{"id":"viet-do","name":"Việt đô","cn":"","capDo":"thanh","parentId":"viet-quoc","blurb":"Kinh thành Việt quốc, nơi ở của gia đình phàm tục mà Hàn Lập được giao đến bảo vệ. Đây là đích đến chính của nhiệm vụ hộ vệ do Lý Hóa Nguyên giao.","detail":"Việt đô là nơi gia đình hậu nhân ân nhân Lý Hóa Nguyên sinh sống. Hàn Lập lẽ ra phải tới đây làm bảo tiêu tạm thời cho gia đình phàm nhân, nhưng trước đó hắn rẽ sang Nguyên Vũ quốc để phó ước Tề Vân Tiêu.","theLucLienQuan":["Bảy phái Việt quốc","Hoàng Phong Cốc"],"nguon":["@c0274"]},{"id":"kim-ma-thanh","name":"Kim Mã thành","cn":"","capDo":"thanh","parentId":"nguyen-vu-quoc","blurb":"Một tiểu thành thuộc Nguyên Vũ quốc, nơi Hàn Lập tìm đến theo lời hẹn với Tề Vân Tiêu. Trong thành có Thanh Tuyền trà quán làm điểm liên hệ.","detail":"Sau bảy tám ngày đêm phi hành, Hàn Lập đến Kim Mã thành, thu Thần Phong chu ngoài thành để tránh kinh động phàm nhân rồi đổi sang dáng vẻ nho sinh. Tại đây hắn hỏi đường đến Thanh Tuyền trà quán để tìm đầu mối gặp Tề Vân Tiêu.","theLucLienQuan":[],"nguon":["@c0274","@c0349"]},{"id":"thanh-tuyen-tra-quan","name":"Thanh Tuyền trà quán","cn":"","aliases":["Thanh Tuyền trà xá","Quán trà Thanh Tuyền"],"capDo":"khac","parentId":"kim-ma-thanh","blurb":"Quán trà tại Kim Mã thành, do một hạ nhân của Tề Vân Tiêu mở. Đây là điểm hẹn để Hàn Lập tìm Tề Vân Tiêu.","detail":"Thanh Tuyền trà quán là địa điểm liên hệ mà Tề Vân Tiêu hẹn Hàn Lập. Khi tới Kim Mã thành, Hàn Lập hỏi đường một hài đồng rồi đứng trước cửa quán, quan sát nơi này với vẻ hứng thú.","theLucLienQuan":[],"nguon":["@c0274"]},{"id":"quan-the-doi-nui-phia-tay-kim-ma-thanh","name":"Quần thể đồi núi phía tây Kim Mã thành","cn":"","capDo":"khac","parentId":"kim-ma-thanh","blurb":"Vùng đồi núi vàng xanh nằm phía tây Kim Mã thành. Chưởng quầy dẫn Hàn Lập đi vòng vèo qua nơi này để tới thung lũng của Tề Vân Tiêu.","detail":"Sau khi rời cửa sau trà quán, chưởng quầy đưa Hàn Lập ra khỏi Kim Mã thành theo hướng tây. Hai người đi qua khu đồi núi lớn nhỏ dày đặc, có màu vàng xanh xen kẽ, trước khi đến nơi ở ẩn có trận pháp của Tề Vân Tiêu.","theLucLienQuan":["Tề gia / người của Tề Vân Tiêu"],"nguon":["@c0275"]},{"id":"thung-lung-noi-o-cua-te-van-tieu","name":"Thung lũng nơi ở của Tề Vân Tiêu","cn":"","capDo":"khac","parentId":"quan-the-doi-nui-phia-tay-kim-ma-thanh","blurb":"Thung lũng bằng phẳng hơn trăm mẫu phía tây Kim Mã thành, nơi Tề Vân Tiêu cư trú và luyện chế. Khu vực có vài gian thạch ốc, trúc xanh và cấm chế bảo vệ.","detail":"Thung lũng có địa thế bằng phẳng, rộng hơn trăm mẫu, bên trong có bảy tám gian thạch ốc màu trắng cùng trúc xanh thưa thớt. Chưởng quầy nhắc Hàn Lập phải đi đúng lộ tuyến vì quanh nơi này có trận pháp hoặc cấm chế, nếu chạm phải sẽ rất phiền toái.","theLucLienQuan":["Tề gia / người của Tề Vân Tiêu"],"nguon":["@c0275"]},{"id":"bich-van-son","name":"Bích Vân sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Bích Vân sơn là ngọn núi gần nơi Tề Vân Tiêu ở, có lá trà thượng hạng dùng chế linh trà.","detail":"Tân Như Âm và nha hoàn tới Bích Vân sơn thu thập lá trà thượng hạng vì nguyên liệu chế linh trà đã hết. Tại đây, nàng bị nhóm tu sĩ Luyện Khí kỳ nhận ra là trận pháp sư và truy đuổi.","theLucLienQuan":[],"nguon":["@c0276"]},{"id":"rung-cay-gan-bich-van-son","name":"Rừng cây gần Bích Vân sơn","cn":"","capDo":"khac","parentId":"bich-van-son","blurb":"Rừng cây gần Bích Vân sơn là nơi Tân Như Âm lập trận phòng hộ để chống nhóm truy đuổi.","detail":"Tân Như Âm dùng trận kỳ tùy thân bố trí một trận pháp đơn giản trong rừng cây này. Hàn Lập, Tề Vân Tiêu và nha hoàn sau đó bay tới bằng Thần Phong chu, thấy nhóm tu sĩ vẫn đang công kích màn thanh quang phòng hộ.","theLucLienQuan":[],"nguon":["@c0276"]},{"id":"cho-o-cua-tan-nhu-am","name":"Chỗ ở của Tân Như Âm","cn":"","capDo":"khac","parentId":null,"blurb":"Chỗ ở của Tân Như Âm nằm về hướng Tây Bắc sau vài canh giờ bay từ hiện trường. Khu vực bề ngoài tầm thường, có sương mù nhàn nhạt và được Hàn Lập đoán có bố trí trận pháp phòng bị.","detail":"Tân Như Âm mời Hàn Lập và Tề Vân Tiêu đến nơi ở để đáp tạ ơn cứu mạng. Khi tiểu chu hạ xuống, Hàn Lập thấy nơi này không có vẻ đặc biệt nhưng vẫn cảnh giác vì chủ nhân là trận pháp sư, rất có thể đã đặt các biện pháp phòng bị quanh chỗ cư trú.","theLucLienQuan":[],"nguon":["@c0277"]},{"id":"nha-truc-giua-suon-nui","name":"Nhà trúc giữa sườn núi","cn":"","capDo":"khac","parentId":"cho-o-cua-tan-nhu-am","blurb":"Cụm nhà trúc giữa sườn núi là nơi Tân Như Âm cư trú và tiếp khách. Hàn Lập cùng Tề Vân Tiêu được đưa vào trúc phòng lớn để nghỉ tạm và uống trà.","detail":"Sau khi đến chỗ ở của Tân Như Âm, cả nhóm tiến vào cụm nhà trúc giữa sườn núi. Tại đây Hàn Lập quan sát sự bồn chồn của Tề Vân Tiêu, uống linh trà và gặp Tân Như Âm khi nàng thay y phục trắng ra kính trà cảm tạ.","theLucLienQuan":[],"nguon":["@c0277"]},{"id":"bac-khu-viet-kinh","name":"Bắc khu Việt Kinh","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Khu phía Bắc của Việt Kinh, cũng là hoàng thành.","detail":"Bắc khu thuộc hoàng thành của Việt Kinh, là nơi cư trú của hoàng thất và không cho người ngoài hoàng thất vào ở.","theLucLienQuan":["Hoàng thất Việt quốc"],"nguon":["@c0278"]},{"id":"nam-khu-viet-kinh","name":"Nam khu Việt Kinh","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Khu phía Nam của Việt Kinh, nơi các quan lại cư trú.","detail":"Nam khu dành cho quan lại lớn nhỏ trong triều đình Việt quốc. Gia đình nào không còn người nhậm chức trong triều thì không được tiếp tục ở lại khu này.","theLucLienQuan":["Quan lại Việt quốc"],"nguon":["@c0278"]},{"id":"khu-phia-tay-kinh-thanh","name":"Khu phía Tây kinh thành","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Khu phía Tây kinh thành là khu nghèo nàn, đối lập với những nơi giàu sang trong Việt Kinh. Nhà cửa nơi đây loàng xoàng, tập trung tạp dịch, tiểu thương, người bán rong, người cùng khổ và đám vô lại nhàn rỗi.","detail":"Chương dùng khu phía Tây để phác họa sự phân tầng trong kinh thành. Cảnh nghèo nàn của nơi này làm nổi bật sự xa hoa của khu phía Đông và quy mô Tần trạch.","theLucLienQuan":[],"nguon":["@c0279"]},{"id":"khu-phia-dong-kinh-thanh","name":"Khu phía Đông kinh thành","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Khu phía Đông kinh thành là nơi nhiều phú thương đại hộ sinh sống. Các nhà giàu dựng trạch viện nguy nga để thể hiện phú quý, trong đó Tần trạch là một siêu cấp trạch viện nổi bật.","detail":"Khu phía Đông được đặt đối lập với khu phía Tây nghèo nàn. Đây là địa bàn của những đại hộ có tài lực lớn nhưng không thuộc khu quan lại, đồng thời là nơi đặt Tần trạch của Tần gia.","theLucLienQuan":["Tần gia"],"nguon":["@c0279"]},{"id":"tan-phu","name":"Tần phủ","cn":"","aliases":["Tần trạch"],"capDo":"khac","parentId":"khu-phia-dong-kinh-thanh","blurb":"Tần phủ, còn gọi là Tần trạch, là siêu cấp trạch viện của Tần gia ở góc khu phía Đông Việt Kinh. Đây là mục tiêu Hàn Lập được Lý Hóa Nguyên giao bí mật bảo vệ.","detail":"Tần trạch rộng hơn mười mẫu, thuộc hàng trạch viện đại phú nổi bật trong khu phía Đông kinh thành. Hàn Lập dùng phong thư và thân phận hậu nhân chi phụ để vào phủ, được đưa tới sương phòng chờ Tần Ngôn hồi phủ xác minh.","theLucLienQuan":["Tần gia"],"nguon":["@c0279"]},{"id":"phong-khach-tan-trach","name":"Phòng khách Tần trạch","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Nơi Tần Ngôn và Tam phu nhân tiếp Hàn Lập khi hắn giả làm thanh niên quê mùa mang thư tới. Phong thư của Lý tiên sư được kiểm tra tại đây trước khi Tần Ngôn mở đọc.","detail":"Phòng khách Tần trạch là nơi diễn ra phần đầu buổi tiếp kiến. Hàn Lập được Tần Bình dẫn vào, Tần Ngôn gọi lão giả áo xanh tóc bạc kiểm tra phong thư, rồi sau khi đọc thư mới chuyển Hàn Lập sang phòng bên để nói chuyện kín.","theLucLienQuan":["Tần gia"],"nguon":["@c0280"]},{"id":"phong-ben-tan-trach","name":"Phòng bên Tần trạch","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Không gian nối từ phòng khách, nơi Tần Ngôn đưa Hàn Lập tới trước khi mở cơ quan vào mật thất. Tam phu nhân bị ngăn không cho theo vào đây.","detail":"Phòng bên Tần trạch là điểm chuyển tiếp từ buổi tiếp khách công khai sang cuộc gặp bí mật. Tại đây Tần Ngôn dùng bình cổ trang trí để mở lối vào mật thất sau vách tường.","theLucLienQuan":["Tần gia"],"nguon":["@c0280"]},{"id":"mat-that-trong-tan-trach","name":"Mật thất trong Tần trạch","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Mật thất ẩn sau vách tường trong phòng bên Tần trạch, có bàn ghế và giá sách. Đây là nơi Tần Ngôn gọi Hàn Lập là tiên sư và nghe tin ma đạo lục tông có thể nhắm vào Tần gia.","detail":"Mật thất trong Tần trạch được mở bằng cơ quan bình cổ, dùng để trao đổi chuyện cơ mật. Sau khi vào đây, Hàn Lập bỏ lớp ngụy trang phàm tục, xác nhận Lý tiên sư là gia sư và trấn an Tần Ngôn rằng hắn sẽ tọa trấn Tần phủ.","theLucLienQuan":["Tần gia"],"nguon":["@c0280"]},{"id":"tam-hop-vien-trong-tan-phu","name":"Tam hợp viện trong Tần phủ","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Tam hợp viện trong Tần phủ là biệt viện thanh nhã, yên tĩnh được dành cho khách quý. Hàn Lập được Tần Bình dẫn tới đây ở lại sau khi Tần Ngôn quyết định an trí hắn trong phủ.","detail":"Đây là một trong những biệt viện tốt trong Tần phủ, nằm trong khuôn viên phủ đệ Tần gia. Tần Bình đưa Hàn Lập tới nơi này, giới thiệu đây là chỗ ở dành cho khách quý và sau đó mang cơm tới cho hắn.","theLucLienQuan":["Tần gia"],"nguon":["@c0281"]},{"id":"tu-lau-hai-tang","name":"Tửu lâu hai tầng","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Tửu lâu hai tầng là nơi Hàn Lập và Tần Bình ghé ăn trưa sau khi dạo phố. Tại lầu hai, Hàn Lập tình cờ phát hiện và nghe lén cuộc nói chuyện của Mông Sơn Ngũ Hữu.","detail":"Tửu lâu có lầu hai, chỗ Hàn Lập ngồi gần cửa sổ cùng Tần Bình. Một bàn khác có ba nam hai nữ tu sĩ Luyện Khí kỳ, từ đó Hàn Lập biết được chuyện Mông Sơn Ngũ Hữu bị kẻ bí ẩn khống chế bằng cấm chế.","theLucLienQuan":["Tần phủ","Mông Sơn Ngũ Hữu"],"nguon":["@c0284"]},{"id":"vuong-phu-hinh-vuong","name":"Vương phủ Hinh Vương","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Vương phủ của Hinh Vương tại Việt kinh. Đây là địa điểm dự kiến mở đại tiệc mừng ái phi khỏi bệnh và mời Tần Ngôn cùng một số hậu bối Tần gia dự yến.","detail":"Hinh Vương gửi thiếp mời Tần gia đến dự đại tiệc mừng ái phi khỏi bệnh. Việc yến tiệc diễn ra tại vương phủ kéo các hậu bối Tần gia ra khỏi phạm vi cấm túc sau hơn hai tháng đề phòng nguy cơ Ma Đạo.","theLucLienQuan":["Hoàng thất Việt Quốc","Tần gia"],"nguon":["@c0285"]},{"id":"dai-sanh-hinh-vuong-phu","name":"Đại sảnh Hinh Vương phủ","cn":"","capDo":"khac","parentId":"vuong-phu-hinh-vuong","blurb":"Không gian chính của yến hội trong Hinh Vương phủ. Tại đây Hinh Vương tiếp khách, giới thiệu Ngô tiên sư và công bố cơ hội thử tiên duyên cho con cháu các nhà.","detail":"Đại sảnh Hinh Vương phủ là nơi các khách khứa tụ tập trong chương này. Hinh Vương cùng Thanh nhi xuất hiện tại đây, kể chuyện cao nhân tu tiên chữa bệnh, rồi để mọi người chuẩn bị đưa con cháu tới gặp Ngô tiên sư.","theLucLienQuan":["Hinh Vương phủ"],"nguon":["@c0287"]},{"id":"dai-sanh-tan-phu","name":"Đại sảnh Tần phủ","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Đại sảnh Tần phủ là nơi Ngô tiên sư thử tiên duyên cho con cháu các nhà trong chương này. Đây cũng là nơi Hàn Lập phát hiện hai tu sĩ che giấu linh khí ở góc bàn.","detail":"Trong đại sảnh, phần lớn khách rời ghế đưa con cháu đến chỗ Ngô tiên sư, còn Hàn Lập ngồi quan sát. Tại đây xảy ra màn nhận diện thiếu nữ giả trai và cuộc giao phong Mộng yểm thuật giữa thanh bào lão giả với Hàn Lập.","theLucLienQuan":["Tần gia"],"nguon":["@c0288"]},{"id":"the-tuc-gioi","name":"Thế tục giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Không gian phàm nhân nơi người tu tiên từng qua lại và làm môn khách cho nhà phú quý. Về sau người tu tiên ít công khai hiện thân hơn do chuyên tâm tranh đoạt cơ hội Trúc Cơ.","detail":"Chương dùng thế tục giới để đối lập với tu tiên giới. Nơi đây từng có một số người tu tiên không giữ được tâm chí tu luyện ở lại hưởng phú quý, nhưng hiện nay việc ấy trở nên hiếm và thường phải che giấu thân phận.","theLucLienQuan":["Hoàng tộc","Hinh Vương phủ","Tần gia","Hoa gia"],"nguon":["@c0290"]},{"id":"tu-tien-gioi","name":"Tu tiên giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Không gian của người tu tiên, nơi việc tu sĩ đi làm môn khách cho phàm nhân bị xem là mất mặt. Thăng Tiên đại hội và hy vọng Trúc Cơ khiến tu sĩ cấp thấp chuyên tâm tranh đoạt cơ duyên.","detail":"Trong chương, tu tiên giới được mô tả qua thái độ khinh thường việc lưu lạc thế tục làm môn khách. Sau khi Thăng Tiên đại hội xuất hiện, người tu tiên càng tập trung vào con đường Trúc Cơ và ẩn cư khổ tu.","theLucLienQuan":["Gia tộc tu tiên"],"nguon":["@c0290"]},{"id":"rung-sau-nui-tham","name":"Rừng sâu núi thẳm","cn":"","capDo":"khac","parentId":"the-tuc-gioi","blurb":"Không gian ẩn cư khổ tu được nhắc tới trong phần giải thích về người tu tiên sau khi Thăng Tiên đại hội xuất hiện. Đây là nơi tu sĩ lui về để chuyên tâm tu luyện công pháp.","detail":"Khi cơ hội Trúc Cơ trở thành trọng tâm, người tu tiên không còn ham làm môn khách thế tục mà thường tìm nơi rừng sâu núi thẳm để khổ tu. Địa danh này mang tính khái quát cho chốn ẩn cư của tu sĩ.","theLucLienQuan":["Gia tộc tu tiên"],"nguon":["@c0290"]},{"id":"cua-sau-hinh-vuong-phu","name":"Cửa sau Hinh Vương phủ","cn":"","capDo":"khac","parentId":"vuong-phu-hinh-vuong","blurb":"Cửa sau vắng người của Hinh Vương phủ, nơi Hàn Lập đứng chờ hai ông cháu Tiêu gia.","detail":"Sau yến hội, Hàn Lập đi dọc bờ tường Hinh Vương phủ tới cửa sau và nhận thấy nơi này vắng người nên không cần dùng pháp thuật che giấu tung tích. Tại đây hắn gặp Tiêu Chấn cùng thiếu nữ họ Tiêu và bắt đầu chất vấn lai lịch họ.","theLucLienQuan":["Hinh Vương phủ","Tiêu gia Phong Hà giản"],"nguon":["@c0291"]},{"id":"nhan-van-tuu-lau","name":"Nhàn Vân tửu lâu","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Tửu lâu nổi danh trong kinh thành, do lão giả Tiêu gia làm ông chủ theo lời Tần Ngôn.","detail":"Khi Hàn Lập hỏi lai lịch hai người Tiêu gia, Tần Ngôn cho biết lão giả là ông chủ Nhàn Vân tửu lâu. Địa điểm này gắn với thân phận thế tục của Tiêu Chấn tại kinh thành.","theLucLienQuan":["Tiêu gia Phong Hà giản"],"nguon":["@c0291"]},{"id":"phong-ha-gian","name":"Phong Hà giản","cn":"","capDo":"khac","parentId":"duan-chau","blurb":"Địa danh ở Duẫn Châu mà Tiêu Chấn tự nhận là nơi Tiêu gia của mình tọa lạc.","detail":"Tiêu Chấn khai với Hàn Lập rằng mình là người của Tiêu gia ở Phong Hà giản, Duẫn Châu. Hàn Lập chưa từng nghe rõ danh xưng này và nghi ngờ lời khai có thể không đáng tin.","theLucLienQuan":["Tiêu gia Phong Hà giản"],"nguon":["@c0291"]},{"id":"duan-chau","name":"Duẫn Châu","cn":"","capDo":"chau","parentId":null,"blurb":"Châu được Tiêu Chấn nhắc tới khi khai lai lịch Tiêu gia Phong Hà giản.","detail":"Duẫn Châu là địa vực mà Tiêu Chấn nói có Phong Hà giản và Tiêu gia của mình. Thông tin này xuất hiện trong lúc Hàn Lập chất vấn thân phận hai ông cháu Tiêu gia.","theLucLienQuan":["Tiêu gia Phong Hà giản"],"nguon":["@c0291"]},{"id":"cho-o-cua-hai-ong-chau-ho-tieu","name":"Chỗ ở của hai ông cháu họ Tiêu","cn":"","aliases":[],"capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập yêu cầu Tiêu Chấn và cháu gái trở về chờ giao dịch.","detail":"Hàn Lập dự định lần theo dấu hiệu truy tung để tìm đến chỗ ở của hai ông cháu họ Tiêu trong đêm, lấy quyển sách vô danh không đầy đủ chứa pháp môn che giấu linh khí.","theLucLienQuan":["Tiêu gia Phong Hà giản"],"nguon":["@c0292"]},{"id":"son-dong-trong-nui-hoang","name":"Sơn động trong núi hoang","cn":"","aliases":[],"capDo":"khac","parentId":null,"blurb":"Nơi thiếu nữ họ Tiêu từng tìm được quyển sách vô danh không đầy đủ.","detail":"Theo lời Tiêu Chấn, thiếu nữ họ Tiêu nhặt được quyển sách vô danh không đầy đủ trong một sơn động khi du ngoạn trên núi hoang. Quyển sách này chứa pháp môn che giấu linh khí khiến Hàn Lập đặc biệt chú ý.","theLucLienQuan":[],"nguon":["@c0292"]},{"id":"khu-phia-sau-cua-vuong-phu","name":"Khu phía sau của Vương phủ","cn":"","capDo":"khac","parentId":"vuong-phu-hinh-vuong","blurb":"Khu vực phía sau vương phủ nơi Hàn Lập lẻn vào sau khi vượt tường. Đây là nơi hắn ẩn thân, quan sát và ra tay với tiểu nha hoàn.","detail":"Sau khi thi triển Ẩn hình thuật và Dẫn khí quyết, Hàn Lập vô thanh vô tức tiến vào khu phía sau của vương phủ. Hắn nấp sau cột hành lang, chọn tiểu nha hoàn từng được Hinh Vương sai đi tìm Tiểu vương gia làm mục tiêu để khống chế thẩm vấn.","theLucLienQuan":["Hinh Vương phủ"],"nguon":["@c0293"]},{"id":"khu-vuon-yen-binh","name":"Khu vườn yên bình","cn":"","capDo":"khac","parentId":"vuong-phu-hinh-vuong","blurb":"Khu vườn trong vương phủ nơi Ngô tiên sư cư trú. Tiểu nha hoàn bị khống chế dẫn Hàn Lập tới đây trước khi được giải thuật.","detail":"Khu vườn yên bình là nơi ở của Ngô tiên sư trong vương phủ. Hàn Lập dùng tiểu nha hoàn dẫn đường tới đây, giải khống chế cho nàng rồi lợi dụng lúc lão đạo chú ý bên ngoài để lẻn vào phòng trước.","theLucLienQuan":["Hinh Vương phủ"],"nguon":["@c0293"]},{"id":"tra-lau-viet-kinh","name":"Trà lâu Việt Kinh","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Trà lâu nơi Hàn Lập ngồi nửa ngày để tự kiểm điểm các việc gần đây.","detail":"Sau khi rời vương phủ, Hàn Lập không quay về Tần Trạch ngay mà vào một trà lâu, chỉ gọi một chén trà rồi ngồi suy xét lại toàn bộ diễn biến gần đây để tìm sơ hở.","theLucLienQuan":[],"nguon":["@c0295"]},{"id":"trang-vien-cu-o-tay-khu","name":"Trang viện cũ ở Tây khu","cn":"","capDo":"khac","parentId":"khu-phia-tay-kinh-thanh","blurb":"Trang viện cũ nơi ông cháu họ Tiêu tạm ẩn sau khi đổi điểm hẹn.","detail":"Nơi này có ba gian phòng cũ, nằm trong Tây khu Việt Kinh. Hàn Lập lần theo tiêu ký tới đây, thu Thần Phong Chu, lặng lẽ áp sát gian phòng giữa để nghe lén rồi hiện thân trước ông cháu họ Tiêu.","theLucLienQuan":["Tiêu gia Phong Hà giản"],"nguon":["@c0295"]},{"id":"bach-duoc-vien","name":"Bách Dược viên","cn":"","capDo":"khac","parentId":"dia-diem-hoang-phong-coc","blurb":"Địa điểm trong Hoàng Phong cốc nơi Hàn Lập bảo cô gái họ Tiêu đến tìm Mã sư huynh. Đây là cơ hội bái sư thay thế sau khi Hàn Lập không nhận nàng làm đồ đệ.","detail":"Hàn Lập giao Truyền Âm phù và ngọc bài cho cô gái họ Tiêu, dặn nàng đến Bách Dược viên của Hoàng Phong cốc tìm vị tiền bối họ Mã. Việc nàng có thể được thu làm đồ đệ hay không phụ thuộc vào vị sư huynh này.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0297"]},{"id":"thon-trang-nho-ngoai-thanh-viet-kinh","name":"Thôn trang nhỏ ngoại thành Việt Kinh","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Thôn nhỏ ngoài Việt Kinh nơi Hàn Lập xuất hiện khi lần theo biến cố của Tử Quang Cảm Ứng châu. Từ đây hắn tiếp tục đến ngọn đồi hẻo lánh gần đó.","detail":"Sau khi viên châu trong tay nứt, Hàn Lập dùng Thần Phong chu rời Tần trạch và tới một thôn nhỏ ngoại thành Việt Kinh. Khu vực này dẫn đến nơi giấu viên Tử Quang châu thứ hai dưới rễ cây dương liễu.","theLucLienQuan":[],"nguon":["@c0297"]},{"id":"ngon-doi-nho-heo-lanh-gan-thon","name":"Ngọn đồi nhỏ hẻo lánh gần thôn","cn":"","capDo":"khac","parentId":"thon-trang-nho-ngoai-thanh-viet-kinh","blurb":"Ngọn đồi cách thôn nhỏ vài dặm, nơi Hàn Lập tìm thấy viên Tử Quang châu bị nứt dưới gốc dương liễu. Sau khi hắn rời đi, bốn người áo đen che mặt từ dưới đất lộ diện gần đó.","detail":"Trên ngọn đồi có cây dương liễu lớn che giấu quang đoàn chứa viên Tử Quang châu thứ hai. Hàn Lập phá cây kiểm tra nhưng không thu được thêm dấu vết; sau đó nhóm áo đen ẩn dưới đất chui lên và bàn về nhiệm vụ bắt sống hoặc giết hắn.","theLucLienQuan":["Nhóm áo đen che mặt"],"nguon":["@c0297"]},{"id":"noi-hoang-da-cach-ngon-doi-hon-tram-dam","name":"Nơi hoang dã cách ngọn đồi hơn trăm dặm","cn":"","capDo":"khac","parentId":"viet-do","blurb":"Địa điểm hoang vắng ngoài khu vực ngọn đồi, nơi Hàn Lập hạ Thần Phong chu sau khi đưa bốn tù binh rời đi.","detail":"Tại nơi này, Hàn Lập buộc bốn người Mông sơn ngũ hữu tháo khăn bịt mặt, xác nhận thân phận của họ và dùng lời uy hiếp để dò hỏi sự liên quan của họ tới các vụ tu sĩ mất tích.","theLucLienQuan":["Mông Sơn Ngũ Hữu","Phe giáo chủ tại Việt Kinh"],"nguon":["@c0299"]},{"id":"viet-kinh","name":"Việt Kinh","cn":"","capDo":"thanh","parentId":null,"blurb":"Việt Kinh là nơi Hàn Lập đến để xử lý việc môn phái của Hoàng Phong cốc. Đây cũng là địa bàn thế lực đang khống chế Mông Sơn ngũ hữu hoạt động và là nơi Tứ muội bị bỏ lại.","detail":"Trong chương 301, Hàn Lập tự nhận đến Việt Kinh để xử lý việc môn phái, còn lão giả mặt đen cho biết Tứ muội đang ở trong một nhà dân tại Việt Kinh thành. Địa điểm này trở thành trung tâm của tuyến đối đầu với phe dùng huyết chú và độc khống chế Mông Sơn ngũ hữu.","theLucLienQuan":["Hoàng Phong cốc","Mông Sơn ngũ hữu","Thế lực dùng huyết chú khống chế Mông Sơn ngũ hữu"],"nguon":["@c0301"]},{"id":"viet-kinh-thanh","name":"Việt Kinh thành","cn":"","capDo":"thanh","parentId":"viet-kinh","blurb":"Việt Kinh thành là khu thành nơi Tứ muội Mông Sơn ngũ hữu đang ẩn trong một nhà dân. Sau khi bốn đồng bạn thất thủ, an nguy của nàng trở thành lý do lão giả mặt đen xin Hàn Lập cứu giúp.","detail":"Lão giả mặt đen nói Tứ muội còn ở lại trong một nhà dân tại Việt Kinh thành và không rõ hiện tại có gặp nguy hay không. Hàn Lập đồng ý nếu nhóm đi theo hắn thì hắn sẽ cứu đồng bạn của họ.","theLucLienQuan":["Mông Sơn ngũ hữu"],"nguon":["@c0301"]},{"id":"phong-khach-tan-phu","name":"Phòng khách Tần phủ","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Phòng khách trong Tần phủ, nơi Tần Ngôn sốt ruột vì Hàn Lập vắng mặt. Tại đây ông sai Tần Bình đi dò tin và tranh luận với Tam phu nhân.","detail":"Đầu chương diễn ra tại phòng khách Tần phủ. Tần Ngôn đi lại lo lắng vì Hàn Lập chưa về, sau đó Tần Bình trở lại báo Hàn Lập đã dẫn khách hồi phủ.","theLucLienQuan":["Tần gia"],"nguon":["@c0302"]},{"id":"thanh-am-vien-phu-can","name":"Thanh Âm viện phụ cận","cn":"","capDo":"khac","parentId":"tan-phu","blurb":"Khu vực gần chỗ ở của Hàn Lập trong Tần phủ. Tần Ngôn cho bố trí Mông Sơn ngũ hữu trú tại đây theo yêu cầu của Hàn Lập.","detail":"Sau khi nghe Tần Bình báo Hàn Lập muốn an bài khách nhân ở gần chỗ mình, Tần Ngôn quyết định dùng khu Thanh Âm viện phụ cận làm nơi trú chân cho họ và dặn không được chậm trễ tiếp đãi.","theLucLienQuan":["Tần gia","Mông Sơn ngũ hữu"],"nguon":["@c0302"]},{"id":"hoang-da-ngoai-thanh-viet-kinh","name":"Hoang dã ngoài thành Việt Kinh","cn":"","capDo":"khac","parentId":"viet-kinh","blurb":"Vùng hoang dã ngoài Việt Kinh, nơi Hàn Lập giải trừ huyết chú cho bốn người trong Mông Sơn ngũ hữu. Đây là bước đầu để nhóm thoát khỏi sự khống chế của Hắc sát giáo.","detail":"Ở vùng hoang dã ngoài thành Việt Kinh, Hàn Lập nhờ thần thức cường đại giải trừ huyết chú cho bốn thành viên Mông Sơn ngũ hữu trước khi lẻn đi cứu người còn lại.","theLucLienQuan":["Mông Sơn ngũ hữu","Hắc sát giáo"],"nguon":["@c0302"]},{"id":"thanh-am-vien","name":"Thanh Âm viện","cn":"","capDo":"khac","parentId":"viet-kinh","blurb":"Đình viện nơi Mông Sơn ngũ hữu tạm trú và chờ hành động ban đêm.","detail":"Sau khi được Tần Bình an trí, Mông Sơn ngũ hữu tụ tập trong phòng khách Thanh Âm viện để chờ thời điểm Hàn Lập đã định. Cũng tại đây, Ngũ muội lén rời sương phòng với hộp nhỏ và bị Hàn Lập cùng các huynh tỷ phát hiện.","theLucLienQuan":["Mông Sơn ngũ hữu"],"nguon":["@c0303"]},{"id":"gia-nguyen-thanh","name":"Gia Nguyên thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Thành trì từng là nơi Lão Tứ và Lão Nhị gặp Hàn Lập trước Thăng Tiên đại hội.","detail":"Trong hồi ức của Lão Tứ, trước khi tham gia Thăng Tiên đại hội, hắn và Lão Nhị từng đến một tửu lầu ở Gia Nguyên thành và gặp một tiểu tu sĩ Luyện Khí kỳ. Người ấy về sau được xác nhận là Hàn Lập hiện tại.","theLucLienQuan":[],"nguon":["@c0303"]},{"id":"hinh-vuong-phu-dia-diem","name":"Hinh Vương phủ","cn":"","capDo":"khac","parentId":"viet-kinh","blurb":"Phủ đệ tại Việt Kinh nơi Hàn Lập và Mông Sơn tứ hữu đột nhập ban đêm.","detail":"Hinh Vương phủ nhốn nháo sau khi Ngô tiên sư biến mất. Đêm đó, Hàn Lập cùng Mông Sơn tứ hữu dùng pháp thuật ẩn thân lẻn vào phủ, tra hỏi thủ vệ rồi tìm đến tiểu lâu của Tiểu vương gia.","theLucLienQuan":["Hinh Vương phủ","Hắc Sát giáo"],"nguon":["@c0305"]},{"id":"tieu-lau-ba-tang-cua-tieu-vuong-gia","name":"Tiểu lâu ba tầng của Tiểu vương gia","cn":"","capDo":"khac","parentId":"hinh-vuong-phu-dia-diem","blurb":"Nơi ở của Tiểu vương gia trong Hinh Vương phủ, bị Hàn Lập bao bằng cách âm kết giới.","detail":"Hàn Lập dẫn người đến tiểu lâu ba tầng của Tiểu vương gia, để Mông Sơn tứ hữu chế trụ thủ vệ bên ngoài rồi tự mình lên tầng ba kiểm tra. Trong phòng không có Tiểu vương gia, chỉ còn một con rối do huyễn thuật biến hóa.","theLucLienQuan":["Hinh Vương phủ","Hắc Sát giáo"],"nguon":["@c0305"]},{"id":"tieu-vien-cua-vuong-tong-quan","name":"Tiểu viện của Vương tổng quản","cn":"","capDo":"khac","parentId":"hinh-vuong-phu-dia-diem","blurb":"Chỗ ở riêng của Vương tổng quản trong Hinh vương phủ.","detail":"Nơi có phòng còn sáng đèn khi nhóm Hàn Lập tới điều tra. Hàn Lập áp sát bên ngoài, dùng pháp quyết che giấu khí tức để nghe lén và phát hiện tiểu vương gia đang ở trong phòng.","theLucLienQuan":["Hinh vương phủ"],"nguon":["@c0306"]},{"id":"mieu-hoang-ngoai-kinh-thanh","name":"Miếu hoang ngoài kinh thành","cn":"","capDo":"khac","parentId":"viet-kinh-thanh","blurb":"Miếu hoang bên ngoài kinh thành, nơi tiểu vương gia dẫn truy binh tới.","detail":"Miếu có Lạc Thạch trận bảo vệ, khiến Mông Sơn tứ hữu ban đầu không thể xông vào. Sau khi Hàn Lập phá trận, phe Hắc Sát giáo xuất hiện phía sau và cho biết trong miếu hiện không có ai, biến nơi này thành điểm dẫn dụ phục kích.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0306"]},{"id":"truong-dau-hien-tai-voi-hac-sat-giao","name":"Trường đấu hiện tại với Hắc Sát giáo","cn":"","capDo":"khac","parentId":null,"blurb":"Trường đấu hiện tại với Hắc Sát giáo là nơi Hàn Lập và Mông Sơn tứ hữu đối đầu Tiểu vương gia, Huyết Thị và Hắc y nhân.","detail":"Địa điểm không nêu tên cụ thể. Tại đây Hắc y nhân triển khai Hắc Phong trận, Hàn Lập phá trận bằng thân pháp, Huyết Thị dùng huyết quang giao chiến và Tiểu vương gia tiếp tục chỉ huy tái lập thế vây.","theLucLienQuan":["Hắc Sát giáo","Mông Sơn tứ hữu"],"nguon":["@c0307"]},{"id":"hoang-thanh-dai-noi-viet-quoc","name":"Hoàng thành đại nội Việt quốc","cn":"","capDo":"khac","parentId":"viet-kinh","blurb":"Khu vực đại nội trong hoàng thành Việt quốc, nơi Hắc Sát giáo chủ ẩn thân.","detail":"Hắc Sát giáo chủ ẩn trong hoàng thành đại nội dưới thân phận đại nội tổng quản Lý Phá Vân. Đây cũng là nơi khiến Hàn Lập khó xử vì đệ tử bảy phái bị cấm bước vào hoàng thành theo quy định bất thành văn.","theLucLienQuan":["Hắc Sát giáo","Bảy phái Việt quốc","Hoàng thất Việt quốc"],"nguon":["@c0310"]},{"id":"hoang-cung-viet-quoc","name":"Hoàng cung Việt quốc","cn":"","capDo":"khac","parentId":"viet-kinh","blurb":"Hoàng cung của Việt quốc, hiện bị Hắc Sát giáo biến thành hang ổ do hoàng đế bị thao túng.","detail":"Hoàng cung Việt quốc là nơi đại nội tổng quản Lý Phá Vân giữ thân phận ngoài sáng. Sau khi hoàng đế bị Hắc Sát giáo chủ thao túng, nơi này trở thành hang ổ của Hắc Sát giáo.","theLucLienQuan":["Hoàng thất Việt quốc","Hắc Sát giáo"],"nguon":["@c0310"]},{"id":"am-huyet-chi-dia-trong-hoang-cung","name":"Âm huyệt chi địa trong Hoàng Cung","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Âm huyệt chi địa trong Hoàng Cung là nơi Giáo chủ Hắc Sát giáo phải dựa vào để thu công trong lần bế quan mấu chốt. Đây là nguyên nhân Hàn Lập cho rằng Hắc Sát giáo khó bỏ sào huyệt rút lui ngay.","detail":"Hàn Lập biết từ Tiểu Vương gia rằng Giáo chủ Hắc Sát giáo đang ở thời điểm bế quan then chốt và cần một vùng Âm huyệt trong Hoàng Cung để hoàn tất việc thu công. Địa điểm này biến Hoàng Cung thành nơi Hắc Sát giáo buộc phải tăng cường phòng bị.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0311"]},{"id":"toa-dien-am-lanh-sau-trong-hoang-cung","name":"Tòa điện âm lãnh sâu trong Hoàng Cung","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Tòa điện âm lãnh sâu trong Hoàng Cung là nơi Thiết La trở về sau khi thoát khỏi Hàn Lập. Băng Yêu ở bên trong điện và đối thoại với hắn về thương thế, Giáo chủ cùng Huyết lao.","detail":"Thiết La khoác áo choàng, cầm Kim bài vượt qua các tầng canh gác trong Đại nội Hoàng Cung rồi đến trước tòa điện âm lãnh này. Không gian này gắn với hoạt động bí mật của Hắc Sát giáo trong Hoàng Cung và là điểm nối tới tin tức về Huyết lao.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0311"]},{"id":"huyet-lao","name":"Huyết lao","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Huyết lao là nơi Thanh Văn và Diệp Xà được nói là đã đến luyện công. Địa điểm này gắn với hoạt động tu luyện tà dị của các thành viên Hắc Sát giáo.","detail":"Trong cuộc đối thoại với Thiết La, Băng Yêu cho biết Thanh Văn và Diệp Xà đã đến Huyết lao luyện công. Thanh Văn đã là Trúc Cơ trung kỳ, còn Diệp Xà cảm ứng dấu hiệu sắp tiến vào Trúc Cơ trung kỳ, cho thấy nơi này liên quan đến việc tăng cường thực lực của Hắc Sát giáo.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0311"]},{"id":"lanh-cung","name":"Lãnh cung","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Khu hẻo lánh trong Hoàng Cung Việt quốc, bình thường ít ai chú ý. Giáo chủ Hắc Sát giáo bế quan bên dưới một hòn giả sơn tại nơi này.","detail":"Lãnh cung là địa điểm Thiết La đi tới để bái kiến giáo chủ Hắc Sát giáo sau thất bại. Bên dưới hòn giả sơn ở đây là nơi giáo chủ đang bế quan, đồng thời cũng là trung tâm ra lệnh án binh cho giáo đồ trong Hoàng Cung.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0312"]},{"id":"nam-o-thanh","name":"Nam Ô thành","cn":"","capDo":"thanh","parentId":"viet-kinh","blurb":"Nam Ô thành là thành gần Việt Kinh, nơi có vài ký danh đệ tử của Huy Minh sư bá đang xử lý sự vụ sư môn. Lưu Tĩnh xem đây là nguồn hỗ trợ có thể tìm đến khi truy quét Hắc Sát giáo gặp khó khăn.","detail":"Trong cuộc bàn bạc về việc xông vào Hoàng Cung, Lưu Tĩnh nhắc rằng trước khi đi, sư phụ từng dặn ở Nam Ô thành gần Việt Kinh có vài ký danh đệ tử của Huy Minh sư bá. Nếu nhóm gặp khó khăn khi đối phó Hắc Sát giáo, họ có thể tìm những người này giúp đỡ.","theLucLienQuan":["Thất đại phái","Môn hạ Lý Hóa Nguyên"],"nguon":["@c0313"]},{"id":"ngu-hoa-vien","name":"Ngự hoa viên","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Khu vực trong Hoàng cung có rừng trúc hoang vắng được Hàn Lập chọn để đặt hậu thủ.","detail":"Hàn Lập lẻn vào Hoàng cung trong đêm, quan sát rồi chọn Ngự hoa viên làm nơi hạ xuống. Khu vực này đủ vắng vẻ để hắn thi triển Cách âm kết giới và bố trí Điên đảo ngũ hành trận mà không kinh động Hắc Sát giáo.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0315"]},{"id":"rung-truc-trong-ngu-hoa-vien","name":"Rừng trúc trong Ngự hoa viên","cn":"","capDo":"khac","parentId":"ngu-hoa-vien","blurb":"Khu rừng trúc hoang vắng trong Ngự hoa viên, nơi Hàn Lập bố trí Điên đảo ngũ hành trận.","detail":"Rừng trúc này có nhiều lá mục, cành rậm rạp và diện tích hơn một mẫu. Hàn Lập thu liễm linh khí, hạ xuống tại đây, dùng kết giới cách âm rồi bố trí một phần Điên đảo ngũ hành trận làm hậu thủ cho trận chiến sắp tới.","theLucLienQuan":["Hắc Sát giáo"],"nguon":["@c0315"]},{"id":"hoa-vien","name":"Hoa viên","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập và Trần Xảo Thiến nói chuyện riêng về chuyện bảy tám năm trước. Sau khi Hàn Lập rời đi, Trần Xảo Thiến ở lại một mình suy nghĩ về nghi vấn của nàng.","detail":"Tại hoa viên, Trần Xảo Thiến dò hỏi Hàn Lập về lần rời cốc trước Huyết sắc thí luyện, còn Hàn Lập dùng lý do mua pháp khí và phù lục để phủ nhận mọi biến cố. Khi hắn rời đi, nàng vẫn tin người năm đó rất có thể là Hàn Lập.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0316"]},{"id":"khach-diem-gan-day","name":"Khách điếm gần đây","cn":"","capDo":"khac","parentId":"viet-kinh","blurb":"Nơi Vũ Huyễn từng trú trước trận đánh Hắc Sát giáo. Lưu Tĩnh đến tìm thì biết hắn rời đi từ sáng hôm trước chưa trở lại, đồ đạc vẫn còn.","detail":"Khách điếm gần Tần phủ là nơi Vũ Huyễn ở lại trước khi nhóm Hoàng Phong cốc xuất phát. Tin từ chủ quán cho thấy Vũ Huyễn không giống đã về cốc vì quần áo thay ra vẫn còn, khiến cả nhóm nghi hoặc về sự mất tích của hắn.","theLucLienQuan":["Hoàng Phong cốc"],"nguon":["@c0316"]},{"id":"tam-cung-cua-hoang-de-viet-quoc","name":"Tẩm cung của Hoàng đế Việt Quốc","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Khu vực trong Hoàng cung Việt Quốc nơi Hoàng đế Việt Quốc cần được giải cứu. Đây là mục tiêu của nhánh Chung Vệ Nương và Trần Xảo Thiến.","detail":"Trong kế hoạch của Lưu Tĩnh, Chung Vệ Nương và Trần Xảo Thiến tách khỏi đội hình chính để đến tẩm cung cứu Hoàng đế Việt Quốc. Việc này nhằm tránh Hắc Sát giáo dùng hoàng đế làm con tin uy hiếp nhóm Hoàng Phong Cốc.","theLucLienQuan":["Hoàng Phong Cốc","Hắc Sát giáo","Hoàng tộc Việt Quốc"],"nguon":["@c0317"]},{"id":"hau-dien","name":"Hậu điện","cn":"","capDo":"khac","parentId":"lanh-cung","blurb":"Khu vực phía sau điện trong Lãnh cung, nơi Băng Yêu sai người tới gọi Huyết Thị khác hỗ trợ.","detail":"Khi Tứ tượng trận có nguy cơ bị phá, Băng Yêu phái người chạy đến Hậu điện để gọi các Huyết Thị khác tới cứu viện, cho thấy đây là tuyến liên lạc nội bộ của phe Hắc Sát giáo trong khu Lãnh cung.","theLucLienQuan":["Hắc Sát giáo","Tứ đại huyết thị"],"nguon":["@c0318"]},{"id":"thai-nam-hoi","name":"Thái Nam hội","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Địa điểm trong hồi tưởng của Hàn Lập, nơi Thanh Văn đạo sĩ năm xưa từng ra sức mời hắn đồng hành.","detail":"Khi gặp lại Thanh Văn trước Lãnh cung, Hàn Lập nhận ra hắn là đạo sĩ từng xuất hiện ở Thái Nam hội. Ký ức này khiến Hàn Lập liên hệ việc mình bị Hoàng y nhân truy sát với đường dây của Thanh Văn.","theLucLienQuan":[],"nguon":["@c0318"]},{"id":"mat-that-ben-duoi-hon-gia-son","name":"Mật thất bên dưới hòn giả sơn","cn":"","capDo":"khac","parentId":"hoang-cung-viet-quoc","blurb":"Mật thất nơi trung niên nhân mắt đỏ của Hắc Sát giáo bế quan.","detail":"Bên dưới hòn giả sơn có mật thất nơi Giáo chủ Hắc Sát giáo đang bế quan. Khi Băng Yêu chết, hắn mở mắt cảm nhận sự việc; trước mặt hắn là thi hài tu sĩ Hoàng Phong cốc bị hút sạch huyết nhục.","theLucLienQuan":["Hắc Sát giáo","Hoàng Phong cốc"],"nguon":["@c0323"]},{"id":"rung-truc","name":"Rừng trúc","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Khu rừng trúc nơi Hàn Lập thu hồi Điên đảo ngũ hành trận sau giao chiến.","detail":"Sau khi trận chiến kết thúc, Hàn Lập lần lượt nhổ toàn bộ trận bàn và trận kỳ của Điên đảo ngũ hành trận khỏi rừng trúc rồi cất đi.","theLucLienQuan":[],"nguon":["@c0331"]},{"id":"tan-gia-dia-diem","name":"Tần gia","cn":"","capDo":"khac","parentId":"kinh-do-viet-quoc","blurb":"Nơi Hàn Lập trở về sau khi rời lãnh cung và gặp Mã sư điệt.","detail":"Tại Tần gia, Mã sư điệt chờ Hàn Lập để giao thủ lệnh triệu tập và ngọc giản của Lý Hóa Nguyên.","theLucLienQuan":["Tần gia","Hoàng Phong Cốc"],"nguon":["@c0331"]},{"id":"kinh-do-viet-quoc","name":"Kinh đô Việt quốc","cn":"","capDo":"thanh","parentId":"viet-quoc","blurb":"Kinh đô nơi nhóm Hàn Lập chuẩn bị rời đi sau biến cố Hắc Sát giáo.","detail":"Sau khi nhận lệnh tập hợp về biên giới, nhóm tu sĩ Hoàng Phong Cốc bàn việc chia nhau rời khỏi kinh đô Việt quốc.","theLucLienQuan":["Hoàng Phong Cốc","Tần gia"],"nguon":["@c0331"]},{"id":"dai-doanh-that-phai-bien-gioi","name":"Đại doanh Thất phái biên giới","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Đại doanh ở biên giới nơi đệ tử Trúc Cơ kỳ trở lên được lệnh tập hợp.","detail":"Thất phái yêu cầu toàn bộ đệ tử Trúc Cơ kỳ trở lên đang làm nhiệm vụ bên ngoài đến đại doanh biên giới trong một tháng để chuẩn bị quyết chiến với Ma đạo lục tông.","theLucLienQuan":["Thất phái","Ma đạo lục tông","Hoàng Phong Cốc"],"nguon":["@c0331"]},{"id":"bach-cuc-son","name":"Bạch Cúc sơn","cn":"","capDo":"khac","parentId":"kinh-do-viet-quoc","blurb":"Danh thắng ngoài kinh đô Việt quốc được Trần Xảo Thiến nhắc đến.","detail":"Trần Xảo Thiến mời Hàn Lập cùng đi xem kỳ cảnh Bạch Cúc sơn trước khi chia tay rời kinh đô.","theLucLienQuan":[],"nguon":["@c0331"]},{"id":"huong-gia-tuu-lau","name":"Hương gia tửu lâu","cn":"","capDo":"khac","parentId":"gia-nguyen-thanh","blurb":"Tửu lâu cũ ở Gia Nguyên thành, nơi Hàn Lập từng ngồi mười năm trước. Trong lần trở lại, hắn ngồi ở lầu hai, quan sát phủ cũ của Mặc phủ và chứng kiến nhóm Hạ thiếu gia bao lầu ba.","detail":"Hàn Lập đến Hương gia tửu lâu sau năm ngày bay về Gia Nguyên thành, chọn lại vị trí gần cửa sổ từng ngồi mười năm trước. Từ đây hắn nhìn sang phủ cũ của Mặc phủ, thấy bảng hiệu đã đổi thành Lý phủ; sau đó nhóm Hạ thiếu gia xuất hiện, gọi chưởng quầy đuổi khách lầu ba để đãi khách quý.","theLucLienQuan":["Tứ Bình bang","Ngũ Sắc môn"],"nguon":["@c0332"]},{"id":"ly-phu","name":"Lý phủ","cn":"","aliases":["Mặc phủ cũ"],"capDo":"khac","parentId":"gia-nguyen-thanh","blurb":"Phủ đệ từng là Mặc phủ ở Gia Nguyên thành, nay đổi bảng thành Lý phủ. Việc đổi chủ khiến Hàn Lập liên hệ đến môn chủ Ngũ Sắc môn họ Lý và càng có ý báo thù cho Mặc phủ.","detail":"Từ Hương gia tửu lâu, Hàn Lập nhìn thấy phủ cũ của Mặc phủ vẫn còn, nhưng bảng hiệu trên cửa lớn đã đổi thành Lý phủ. Hắn nhớ môn chủ Ngũ Sắc môn hình như họ Lý, nghi nơi này bị chiếm làm chỗ ở, nên cảm thấy khó chịu.","theLucLienQuan":["Mặc phủ","Ngũ Sắc môn"],"nguon":["@c0332"]},{"id":"tong-da-tu-binh-bang","name":"Tổng đà Tứ Bình bang","cn":"","capDo":"khac","parentId":"gia-nguyen-thanh","blurb":"Tổng đà Tứ Bình bang là nơi đặt căn cứ hiện thời của Tứ Bình bang trong Gia Nguyên thành. Nơi này đã dời tới khu phố giàu có sau khi bang phái phất lên.","detail":"Hàn Lập lẻn vào hậu viện tổng đà Tứ Bình bang để gặp lại Tôn Nhị Cẩu. Tổng đà hiện nằm ở một góc đường phố giàu có, phản ánh vị thế đã tăng của bang này.","theLucLienQuan":["Tứ Bình bang"],"nguon":["@c0333"]},{"id":"vung-nui-gan-gia-nguyen-thanh","name":"Vùng núi gần Gia Nguyên thành","cn":"","capDo":"khac","parentId":"gia-nguyen-thanh","blurb":"Khu vực miền núi cách Gia Nguyên thành khoảng trăm dặm, nơi Khúc Hồn quanh quẩn sau khi rời Tứ Bình bang.","detail":"Sau khi phá tường bỏ chạy khỏi nơi Tứ Bình bang quản thúc, Khúc Hồn không rời quá xa mà quanh quẩn trong vùng núi gần Gia Nguyên thành. Tôn Nhị Cẩu phái người theo dõi nơi này, nhưng mỗi lần hắn tự mang Dẫn Hồn chung tới gần thì Khúc Hồn lại lẩn đi nơi khác.","theLucLienQuan":["Tứ Bình bang"],"nguon":["@c0334"]},{"id":"tong-dan-cu-cua-ngu-sac-mon","name":"Tổng đàn cũ của Ngũ Sắc môn","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm cũ của Ngũ Sắc môn, được nghe nói là nơi con lớn của môn chủ Ngũ Sắc môn tọa trấn.","detail":"Tôn Nhị Cẩu báo với Hàn Lập rằng con lớn của môn chủ Ngũ Sắc môn nghe nói đang tọa trấn tại tổng đàn cũ của Ngũ Sắc môn.","theLucLienQuan":["Ngũ Sắc môn"],"nguon":["@c0334"]},{"id":"vung-nui-rung-ngoai-gia-nguyen-thanh-hon-tram-dam","name":"Vùng núi rừng ngoài Gia Nguyên thành hơn trăm dặm","cn":"","aliases":[],"capDo":"khac","parentId":"gia-nguyen-thanh","blurb":"Khu núi cao rừng rậm ít người qua lại ở ngoài Gia Nguyên thành.","detail":"Khúc Hồn sau dị biến ẩn tới vùng núi rừng hoang vắng này. Hàn Lập dùng Dẫn Hồn chung truy tới đây để tìm hắn.","theLucLienQuan":[],"nguon":["@c0337"]},{"id":"thien-do-quoc","name":"Thiên Đô quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia nơi Ngự Linh tông tọa lạc. Tu sĩ đang chiếm thân Khúc Hồn tự nhận là tu sĩ Ngự Linh tông của Thiên Đô quốc.","detail":"Thiên Đô quốc được nhắc khi tu sĩ trong thân Khúc Hồn khai thân phận thật với Hàn Lập. Đây là địa bàn xuất thân của Ngự Linh tông, một tông môn ma đạo có liên hệ bí mật với Linh Thú Sơn.","theLucLienQuan":["Ngự Linh tông"],"nguon":["@c0339"]},{"id":"son-dong-giau-tui-tru-vat","name":"Sơn động giấu túi trữ vật","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Sơn động gần nơi Khúc Hồn bị khống chế, được nói là chỗ cất túi trữ vật chứa ngọc giản. Bên trong có đống xương thú và quái vật phục kích Hàn Lập.","detail":"Khúc Hồn chỉ Hàn Lập đến sơn động này để tìm chứng cứ về ngọc giản gửi Linh Thú sơn. Khi Hàn Lập dùng Nguyệt Quang thạch soi sáng và tiến vào, hắn phát hiện những khối tưởng như đá thực ra là xương thú còn máu thịt và dấu răng, sau đó bị bóng đen tập kích.","theLucLienQuan":["Ngự Linh Tông","Linh Thú sơn"],"nguon":["@c0340"]},{"id":"dai-doanh-that-phai-lien-quan","name":"Đại doanh Thất phái liên quân","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Đại doanh của Thất phái và liên quân được Khúc Hồn nói là mục tiêu Ma đạo có thể đánh úp. Thời điểm tập kích có thể đến trước ngày quyết chiến chính thức.","detail":"Theo lời Khúc Hồn, thời gian hẹn quyết chiến chỉ để mê hoặc đối phương. Ma đạo có thể nhân lúc Thất phái lơi lỏng và nhân thủ chưa đủ để tập kích đại doanh trong vài ngày tới.","theLucLienQuan":["Thất phái","Ma đạo lục tông","Linh Thú sơn"],"nguon":["@c0340"]},{"id":"khu-rung-ram-ben-duoi","name":"Khu rừng rậm bên dưới","cn":"","capDo":"khac","parentId":null,"blurb":"Khu rừng rậm bên dưới là nơi Hàn Lập lao xuống để thực hiện kế ẩn thân khi bị bọ ngựa yêu thú truy đuổi.","detail":"Trong lúc Thần Phong Chu không thể cắt đuôi yêu thú, Hàn Lập chuyển hướng lao xuống khu rừng rậm. Hắn tung pháp khí thường và khôi lỗi binh sĩ làm mồi nhử, rồi khoác Ẩn Linh sa trốn sau đại thụ để che giấu khí tức.","theLucLienQuan":[],"nguon":["@c0341"]},{"id":"mat-that-linh-nhan-chi-tuyen","name":"Mật thất Linh Nhãn chi tuyền","cn":"","capDo":"khac","parentId":"dong-phu-han-lap","blurb":"Mật thất Linh Nhãn chi tuyền nằm trong động phủ Hàn Lập. Đây là nơi hai trứng Bạch Tri chu nở thành công.","detail":"Khi Hàn Lập trở về động phủ, hắn tới mật thất này kiểm tra và thấy hai Bạch Tri chu non nổi trong dòng suối. Nơi đây gắn với việc linh trùng nở và nhận chủ nhờ cấm chế tinh huyết.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0345"]},{"id":"thien-thach-phong","name":"Thiên Thạch Phong","cn":"","capDo":"khac","parentId":"dia-diem-hoang-phong-coc","blurb":"Một địa điểm thuộc phạm vi Hoàng Phong Cốc, nơi Hoàng sư thúc đang ở trong lúc môn phái triệu tập khẩn.","detail":"Khi Chung Linh Đạo bẩm báo với Lệnh Hồ lão tổ tại Nghị Sự điện, ông cho biết Hoàng sư thúc đang ở Thiên Thạch Phong nên nhất thời khó có thể đến kịp. Địa điểm này vì vậy được nhắc trong bối cảnh Hoàng Phong Cốc triệu tập tu sĩ Trúc Cơ trở lên.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0346"]},{"id":"phong-tuyen-thu-hai","name":"Phòng tuyến thứ hai","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Tuyến phòng thủ còn lại của Thất phái sau khi tiền phương đại bại. Nơi này chỉ miễn cưỡng chống đỡ để tranh thủ thêm ít ngày.","detail":"Sau khi liên quân Thất phái ở tiền phương đại bại, số tu sĩ còn lại lui về phòng tuyến thứ hai và chỉ có thể miễn cưỡng chống đỡ. Lệnh Hồ lão tổ nhận định tuyến này nhiều nhất chỉ tranh thủ thêm khoảng hai, ba ngày cho Hoàng Phong Cốc rút lui.","theLucLienQuan":["Thất phái","Hoàng Phong Cốc","Ma đạo lục tông"],"nguon":["@c0346"]},{"id":"nghi-su-dai-dien","name":"Nghị sự đại điện","cn":"","capDo":"khac","parentId":"dia-diem-hoang-phong-coc","blurb":"Nghị sự đại điện là nơi đội triệt ly của Hoàng Phong Cốc tập kết trước khi rời cốc. Hàn Lập quay lại đây sau khi thu dọn động phủ.","detail":"Tại Nghị sự đại điện, Hàn Lập thấy ngoài vài chục tu sĩ Trúc Cơ còn có mấy trăm đệ tử Luyện Khí được chọn mang đi. Lệnh Hồ lão tổ và Hoàng sư thúc xuất hiện tại đây để ra lệnh xuất phát khi biết Ma đạo đã lộ tung tích.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0347"]},{"id":"bien-gioi-viet-quoc-nguyen-vu-quoc","name":"Biên giới Việt Quốc — Nguyên Vũ Quốc","cn":"","aliases":[],"capDo":"khac","parentId":null,"blurb":"Biên giới giữa Việt Quốc và Nguyên Vũ Quốc là nơi Hàn Lập tới sau hai ngày bỏ chạy khỏi vòng vây Ma đạo. Sau khi hắn vượt qua, Ma đạo lập đội giám sát để chặn những tu sĩ đến sau.","detail":"Hàn Lập nhìn lại dãy núi Việt Quốc tại biên giới rồi đưa Khúc Hồn tiến vào Nguyên Vũ Quốc. Nửa ngày sau, hơn vài chục tu sĩ Ma đạo xuất hiện và đồn trú tại khu vực này, kiểm soát dải biên giới liên miên mấy trăm dặm để tiêu diệt tu sĩ muốn trốn sang Nguyên Vũ Quốc.","theLucLienQuan":["Ma đạo","Đội Ma đạo canh biên giới Việt — Nguyên Vũ"],"nguon":["@c0349"]},{"id":"day-nui-phia-tay-kim-ma-thanh","name":"Dãy núi phía tây Kim Mã Thành","cn":"","aliases":[],"capDo":"vuc","parentId":"kim-ma-thanh","blurb":"Dãy núi phía tây Kim Mã Thành là khu vực đặt chỗ ở của Tề Vân Tiêu. Hàn Lập từ trên cao quan sát hồi lâu mới nhận ra vị trí cần tìm.","detail":"Khu vực núi non phía tây Kim Mã Thành là nơi Tề Vân Tiêu từng cư trú. Khi Hàn Lập tới đây, hắn phải phân biệt từ trên cao một hồi mới tìm ra thung lũng có thạch ốc, nhà trúc và trận pháp phòng hộ đã bị phá.","theLucLienQuan":[],"nguon":["@c0349"]},{"id":"cho-o-cua-te-van-tieu","name":"Chỗ ở của Tề Vân Tiêu","cn":"","aliases":[],"capDo":"khac","parentId":"day-nui-phia-tay-kim-ma-thanh","blurb":"Chỗ ở của Tề Vân Tiêu là một thung lũng có thạch ốc, nhà trúc và trận pháp phòng hộ. Khi Hàn Lập tới, nơi này đã bị phá hủy hơn phân nửa và chỉ còn thi thể chưởng quầy trà lâu.","detail":"Tại thung lũng nơi Tề Vân Tiêu từng ở, Hàn Lập thấy thạch ốc, nhà trúc xiêu vẹo và trận pháp phòng hộ bị địch nhân phá hỏng. Trong căn phòng có một thi thể thối rữa, được Hàn Lập nhận ra là chưởng quầy trà lâu chứ không phải Tề Vân Tiêu, khiến tung tích Tề Vân Tiêu vẫn bỏ ngỏ.","theLucLienQuan":[],"nguon":["@c0349"]},{"id":"noi-o-cua-te-van-tieu","name":"Nơi ở của Tề Vân Tiêu","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Chỗ ở của Tề Vân Tiêu đã bị phá hủy, nơi Hàn Lập gặp hai tu sĩ Phó gia. Tại đây hắn biết Tề Vân Tiêu còn sống và truy ra nguyên nhân Phó gia nhắm vào Tề Vân Tiêu.","detail":"Địa điểm này là hiện trường sau vụ công kích Tề Vân Tiêu. Hàn Lập đối chất với lão giả Phó gia và người thành niên Phó gia tại đây rồi giết cả hai sau khi xác định không còn kẻ khác.","theLucLienQuan":["Phó gia","Tề gia"],"nguon":["@c0350"]},{"id":"tieu-son-vo-danh-noi-o-tan-nhu-am","name":"Tiểu sơn vô danh nơi ở Tân Như Âm","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Ngọn núi nhỏ ẩn cư của Tân Như Âm, được trận sương mù che giấu. Hàn Lập đến đây sau khi giết hai tu sĩ Phó gia và dùng Truyền Âm phù xin vào.","detail":"Nơi này có sương mù và trận pháp phòng hộ, khi nhận tín hiệu thì biến cảnh quanh Hàn Lập thành rừng đại thụ ảo hóa rồi mở thông đạo. Sự nguyên vẹn của sương mù khiến Hàn Lập yên tâm phần nào rằng Tân Như Âm chưa bị hạ độc thủ.","theLucLienQuan":[],"nguon":["@c0350"]},{"id":"quan-the-nha-bang-truc-cua-tan-nhu-am","name":"Quần thể nhà bằng trúc của Tân Như Âm","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Khu trúc ốc nơi Tân Như Âm ở và tiếp Hàn Lập.","detail":"Hàn Lập từng đến nơi này trước đó. Trong lần trở lại, hắn thấy Tân Như Âm và Tiểu Mai mặc áo trắng đứng trước trúc ốc, bên trong đặt linh vị Tề Vân Tiêu.","theLucLienQuan":["Tân Như Âm"],"nguon":["@c0351"]},{"id":"thong-dao-dan-vao-noi-o-tan-nhu-am","name":"Thông đạo dẫn vào nơi ở Tân Như Âm","cn":"","capDo":"khac","parentId":"quan-the-nha-bang-truc-cua-tan-nhu-am","blurb":"Thông đạo mà Hàn Lập dùng để tiến vào khu trúc ốc của Tân Như Âm.","detail":"Sau khi Tân Như Âm xác nhận Khúc Hồn không phải người sống, Hàn Lập điều khiển Thần Phong Chu bay ra khỏi thông đạo này để vào nơi ở của nàng.","theLucLienQuan":["Tân Như Âm"],"nguon":["@c0351"]},{"id":"phuong-thi-gan-noi-o-tan-nhu-am","name":"Phường thị gần đó","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Phường thị nơi Tề Vân Tiêu đi tìm tài liệu trận pháp cho Tân Như Âm.","detail":"Vì thiếu tài liệu trận pháp hiếm, Tề Vân Tiêu thay Tân Như Âm tới phường thị này, từ đó bị tu sĩ Phó gia phát hiện và truy bắt.","theLucLienQuan":["Phó gia","Tân Như Âm"],"nguon":["@c0351"]},{"id":"cho-o-cu-cua-te-van-tieu","name":"Chỗ ở cũ của Tề Vân Tiêu","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Nơi Tề Vân Tiêu từng ở, có đại trận và huyễn trận phòng hộ.","detail":"Phó gia truy tìm tới chỗ ở này, bị đại trận bên ngoài sát thương hơn mười tu sĩ, sau đó mời cao thủ Kết Đan kỳ phá trận. Sau biến cố, Phó gia còn để người ngày đêm giám thị tại đây.","theLucLienQuan":["Phó gia","Tề Vân Tiêu"],"nguon":["@c0351"]},{"id":"phuong-thi-nguyen-vu-quoc","name":"Phường thị Nguyên Vũ quốc","cn":"","aliases":[],"capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Phường thị tại Nguyên Vũ quốc trở nên hưng vượng bất thường sau khi tin thảm bại của tu sĩ hai nước và Việt quốc truyền tới. Nhiều tu sĩ kéo đến đổi mua vật phẩm để tăng sức tự vệ.","detail":"Sau khi tin chiến bại lan đến Nguyên Vũ quốc, gia tộc tu tiên và tán tu đều hoang mang, khiến phường thị xuất hiện nhiều pháp khí, đan dược và vật phẩm quý hơn trước. Hàn Lập đi dạo một vòng, mua được dược tài lạ rồi tới Tinh Trần các ở trung tâm phường thị.","theLucLienQuan":["Tinh Trần các"],"nguon":["@c0353"]},{"id":"tinh-tran-cac-tang-sau","name":"Tinh Trần các tầng sáu","cn":"","capDo":"khac","parentId":"tinh-tran-cac","blurb":"Tầng giao dịch cao hơn của Tinh Trần các. Hàn Lập được Lam phu nhân dẫn lên đây để thương lượng các món vượt quyền quyết định của nàng.","detail":"Tinh Trần các tầng sáu là nơi xử lý giao dịch đắt giá như hai phương thuốc Trúc Cơ kỳ và một bộ pháp khí đỉnh giai. Muốn lên đây, Hàn Lập phải chứng minh có hơn một ngàn linh thạch hoặc vật phẩm tương đương.","theLucLienQuan":["Tinh Trần các"],"nguon":["@c0354"]},{"id":"dai-sanh-tinh-tran-cac","name":"Đại sảnh Tinh Trần các","cn":"","capDo":"khac","parentId":"tinh-tran-cac","blurb":"Không gian tiếp khách và bày trân phẩm trong Tinh Trần các. Đây là nơi Hàn Lập, Khúc Hồn, tu sĩ họ Phiền và Lam phu nhân gặp nhau.","detail":"Tại đại sảnh Tinh Trần các, Lam phu nhân cho khôi lỗi mang khay trân phẩm ra, giới thiệu các pháp khí và hoàn tất giao dịch Hàn Tinh nhận với tu sĩ họ Phiền. Hàn Lập cũng tại đây nêu nhu cầu mua đan phương Trúc Cơ kỳ hoặc pháp khí thành bộ.","theLucLienQuan":["Tinh Trần các"],"nguon":["@c0354"]},{"id":"phuong-thi","name":"Phường thị","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Khu phường thị nơi Hàn Lập vừa giao dịch tại Tinh Trần các, nghỉ ở khách điếm và tới cửa tiệm của Từ điếm chủ luyện khí. Sau khi rời phạm vi cấm chế, hắn bay tới tiểu sơn của Tân Như Âm.","detail":"Phường thị này có Tinh Trần các, khách điếm và cửa tiệm luyện khí của Từ điếm chủ. Hàn Lập hoàn tất giao dịch, chờ đúng hẹn luyện khí hơn nửa tháng rồi rời khỏi phạm vi cấm chế để đi tiếp.","theLucLienQuan":["Tinh Trần các"],"nguon":["@c0356"]},{"id":"khach-diem-trong-phuong-thi","name":"Khách điếm trong phường thị","cn":"","capDo":"khac","parentId":"phuong-thi","blurb":"Nơi Hàn Lập nghỉ lại một đêm sau khi rời Tinh Trần các. Hắn ngồi luyện khí và chuẩn bị tới chỗ Từ điếm chủ vào ngày hôm sau.","detail":"Khách điếm nằm trong phường thị, được Hàn Lập dùng làm nơi tạm nghỉ trước khi đem tài liệu tới luyện chế pháp khí.","theLucLienQuan":[],"nguon":["@c0356"]},{"id":"cua-tiem-cua-tu-diem-chu","name":"Cửa tiệm của Từ điếm chủ","cn":"","capDo":"khac","parentId":"phuong-thi","blurb":"Nơi Hàn Lập giao tài liệu cho Từ điếm chủ luyện khí hơn nửa tháng. Kết quả phần lớn tài liệu trân quý bị hủy, chỉ luyện thành bộ phi đao từ chân Bạch Tri chu.","detail":"Cửa tiệm có hậu viện luyện khí, nơi Từ điếm chủ tiếp nhận tài liệu cao cấp của Hàn Lập. Lần luyện chế này khiến Hàn Lập rút ra rằng tài liệu càng cao cấp càng cần luyện khí sư tay nghề cao.","theLucLienQuan":[],"nguon":["@c0356"]},{"id":"truc-oc-noi-o-tan-nhu-am","name":"Trúc ốc","cn":"","capDo":"khac","parentId":"tieu-son-vo-danh-noi-o-tan-nhu-am","blurb":"Căn trúc ốc nơi Hàn Lập và Tân Như Âm đối diện trao đổi. Tại đây nàng báo việc sửa xong Truyền Tống trận cổ xưa và tặng trận kỳ, trận bàn cho hắn.","detail":"Trúc ốc thuộc nơi ở của Tân Như Âm trên tiểu sơn vô danh. Cuộc gặp trong trúc ốc gắn với việc trao ngọc giản sửa trận, gửi gắm trận cụ và lời hứa báo thù Phó gia.","theLucLienQuan":[],"nguon":["@c0356"]},{"id":"bach-tri-son","name":"Bạch Trì sơn","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Điểm tụ hội tu tiên giả gần nhất mà Hàn Lập tới để nghe ngóng tin tức chiến cuộc Việt quốc. Núi có ba đỉnh, đỉnh phía Tây là nơi tụ hội.","detail":"Bạch Trì sơn là nơi tán tu và tu sĩ gia tộc tu tiên thường tụ hội, trao đổi tin tức và giao dịch vật phẩm. Hàn Lập đến đây để tìm hiểu mức độ ác liệt của Tu tiên giới Việt quốc và cơ hội xoay chuyển của Thất phái trước khi định kế hoạch tiếp theo.","theLucLienQuan":["Thất phái"],"nguon":["@c0356"]},{"id":"dinh-nui-phia-tay-cua-bach-tri-son","name":"Đỉnh núi phía Tây của Bạch Trì sơn","cn":"","capDo":"khac","parentId":"bach-tri-son","blurb":"Khu vực trên Bạch Trì sơn nơi Hàn Lập hạ xuống trong tiểu hội tu sĩ. Tại đây có cổ tự, hơn mười thạch đình và nhiều tu sĩ tụ tập nói chuyện.","detail":"Đỉnh Tây Bạch Trì sơn là nơi Hàn Lập quan sát trước khi hạ xuống cùng Khúc Hồn. Hắn đi về phía các thạch đình gần đó để nghe nhóm tu sĩ bàn về chiến sự Ma đạo và tình hình Việt quốc.","theLucLienQuan":[],"nguon":["@c0357"]},{"id":"vo-bien-hai","name":"Vô biên hải","cn":"","capDo":"vuc","parentId":"thien-nam","blurb":"Vô biên hải là vùng biển cực Bắc khu Thiên Nam, rộng lớn và nguy hiểm đến mức được xem là không thể vượt qua. Ngay cả tiền lệ tu sĩ Nguyên Anh bay hơn một năm cũng không thấy bờ, khiến Hàn Lập loại bỏ đường Bắc.","detail":"Vô biên hải nằm ở cực Bắc khu Thiên Nam, nước biển vẩn đục, hiếm sinh vật, các loài sống được đều hung dữ. Tu sĩ Kết Đan tiến vào cũng nguy hiểm, còn một cao nhân Nguyên Anh từng chuẩn bị đầy đủ bay hơn một năm vẫn không thấy đầu kia và phải quay về.","theLucLienQuan":[],"nguon":["@c0358"]},{"id":"mo-lan-dai-thao-nguyen","name":"Mộ Lan đại thảo nguyên","cn":"","aliases":["Thảo nguyên Mộ Lan"],"capDo":"vuc","parentId":"thien-nam","blurb":"Mộ Lan đại thảo nguyên là vùng thảo nguyên rộng lớn nơi Mộ Lan tộc sinh sống. Địa bàn này nghèo tài nguyên tu luyện nhưng có nhiều bộ lạc du mục và pháp sĩ Mộ Lan.","detail":"Mộ Lan đại thảo nguyên nằm sát chín quốc gia của Cửu quốc minh, là nơi tồn tại hàng ngàn hàng vạn bộ lạc Mộ Lan. Do linh mạch và mỏ linh thạch trên thảo nguyên nghèo nàn, pháp sĩ Mộ Lan từng nhòm ngó tài nguyên của chín quốc gia bên cạnh, dẫn tới chiến tranh lâu dài.","theLucLienQuan":["Mộ Lan tộc","Pháp sĩ Mộ Lan tộc","Cửu quốc minh"],"nguon":["@c0358"]},{"id":"thien-lan-thao-nguyen","name":"Thiên Lan thảo nguyên","cn":"","capDo":"vuc","parentId":"thien-nam","blurb":"Thiên Lan thảo nguyên là địa bàn của Đột Ngột nhân ở đầu kia thảo nguyên. Khu vực này gắn với tín ngưỡng Thiên Lan thú và mối đối địch nhiều đời giữa Đột Ngột nhân với Mộ Lan tộc.","detail":"Thiên Lan thảo nguyên được nhắc khi mở rộng bối cảnh ngoài Mộ Lan đại thảo nguyên. Đây là nơi Đột Ngột nhân sinh sống, một dân tộc du mục tin thờ Thiên Lan thú và nhiều đời giao chiến sinh tử với Mộ Lan tộc.","theLucLienQuan":["Đột Ngột nhân","Mộ Lan tộc"],"nguon":["@c0358"]},{"id":"mo-linh-thach-chua-truyen-tong-tran-co","name":"Mỏ linh thạch chứa Truyền Tống trận cổ","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Mỏ linh thạch ở Việt quốc đã rơi vào tay Ma đạo, gần nơi có động quật chứa Truyền Tống trận cổ.","detail":"Hàn Lập trở lại khu vực mỏ linh thạch và phát hiện nơi này đã bị đệ tử Quỷ Linh môn cùng Hợp Hoan tông chiếm giữ. Dù vậy, động quật dưới đất gần đó vẫn còn Truyền Tống trận cổ mà hắn cần sửa chữa.","theLucLienQuan":["Ma đạo","Quỷ Linh môn","Hợp Hoan tông"],"nguon":["@c0359"]},{"id":"dong-quat-duoi-dat-gan-mo-linh-thach","name":"Động quật dưới đất gần mỏ linh thạch","cn":"","capDo":"khac","parentId":"mo-linh-thach-chua-truyen-tong-tran-co","blurb":"Nơi cất giữ Truyền Tống trận cổ mà Hàn Lập mở lại và tu bổ.","detail":"Hàn Lập phá đá mở lại động quật, xác nhận Truyền Tống trận cổ vẫn còn, rồi dùng trận kỳ huyễn hình và Điên Đảo Ngũ Hành trận cải tiến để che giấu, phòng thủ trong lúc sửa trận.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0359"]},{"id":"tieu-phuong-thi-phia-dong-mo-linh-thach","name":"Tiểu phường thị phía đông mỏ linh thạch","cn":"","capDo":"khac","parentId":"mo-linh-thach-chua-truyen-tong-tran-co","blurb":"Tiểu phường thị do một gia tộc tu tiên mở, được Hàn Lập nhắm tới để mua thêm vật liệu sửa trận.","detail":"Khi vật liệu tu bổ Truyền Tống trận cạn, Hàn Lập nhớ phía đông mỏ linh thạch từng có một tiểu phường thị của gia tộc tu tiên, nơi có thể tìm mua thiết mẫu, tinh ngọc và các vật liệu thông thường.","theLucLienQuan":["Gia tộc tu tiên"],"nguon":["@c0359"]},{"id":"rung-ram-phia-duoi","name":"Rừng rậm phía dưới","cn":"","capDo":"khac","parentId":null,"blurb":"Khu rừng bên dưới nơi Hàn Lập ẩn thân trong lúc quan sát cuộc truy sát Nam Cung Uyển.","detail":"Từ khu rừng này, Hàn Lập phóng bạch quang lên cứu Nam Cung Uyển rồi rút xuống để dẫn Vương Thiền và Điền công tử vào bẫy trận.","theLucLienQuan":["Ma đạo"],"nguon":["@c0360"]},{"id":"khu-vuc-ao-tran-cot-da","name":"Khu vực ảo trận cột đá","cn":"","capDo":"khac","parentId":"rung-ram-phia-duoi","blurb":"Không gian ảo trận nơi Vương Thiền và Điền công tử rơi vào sau khi truy kích Hàn Lập.","detail":"Khi hai truy binh lao xuống theo Hàn Lập, cảnh rừng biến mất và bốn phía hiện ra vô số cột đá cực lớn, cho thấy họ đã bị nhốt trong ảo trận.","theLucLienQuan":["Ma đạo"],"nguon":["@c0360"]},{"id":"thu-dong-kho-rao","name":"Thụ động khô ráo","cn":"","capDo":"khac","parentId":null,"blurb":"Hang cây khô ráo nơi Hàn Lập đưa nữ tử che mặt vào sau khi thoát truy đuổi.","detail":"Tại thụ động này, Hàn Lập kiểm tra thương thế cho nữ tử che mặt bằng linh lực nhưng bị cơ thể nàng hút pháp lực, khiến tu vi rơi mạnh rồi hôn mê.","theLucLienQuan":[],"nguon":["@c0361"]},{"id":"dong-quat-chua-co-truyen-tong-tran","name":"Động quật chứa cổ Truyền tống trận","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Động quật nơi Hàn Lập quay lại sau khi rời thụ động, sửa xong cổ Truyền tống trận và bố trí Điên đảo ngũ hành trận che chở. Nơi này bị Vương Thiền cùng tu sĩ ma đạo phát hiện khi cổ trận phát động quá mạnh.","detail":"Động quật chứa cổ Truyền tống trận là nơi Khúc Hồn ngồi chờ và Hàn Lập dốc sức sửa trận trong sáu bảy ngày. Khi Hàn Lập dùng linh thạch bậc trung thử phát động, hoàng quang xuyên qua động khẩu và cấm chế, khiến vị trí bị lộ; sau đó Vương Thiền, Lý thị huynh đệ và đoàn tu sĩ ma đạo phá mở phía trên động quật.","theLucLienQuan":["Ma đạo","Quỷ linh môn"],"nguon":["@c0363"]},{"id":"thien-nam-tu-tien-gioi","name":"Thiên Nam Tu Tiên Giới","cn":"","capDo":"vuc","parentId":"thien-nam","blurb":"Khu vực tu tiên giới mà Hàn Lập rời khỏi sau khi dùng cổ Truyền tống trận. Sau khi hắn rời đi, nơi này tiếp tục biến động với chính đạo, ma đạo và Thiên đạo hội.","detail":"Thiên Nam Tu Tiên Giới là nơi diễn ra các biến động hậu chương: Thiên đạo hội thành lập, chính đạo và ma đạo tiếp tục giao chiến, lục đạo tông phái dàn xếp với Cửu Quốc Minh và chiến sự với Pháp Sĩ khiến nhiều tu sĩ chết trận. Hàn Lập đã rời khỏi khu vực này nên không biết các hỗn loạn về sau.","theLucLienQuan":["Ma đạo","Chính đạo","Thiên đạo hội","Cửu Quốc Minh","Lục đạo tông phái"],"nguon":["@c0363"]},{"id":"chin-nuoc-dia-ban-cuu-quoc-minh","name":"Chín nước / địa bàn Cửu Quốc Minh","cn":"","capDo":"vuc","parentId":"thien-nam-tu-tien-gioi","blurb":"Khu vực gắn với Cửu Quốc Minh và bị đặt trong nguy cơ Mộ Lan gia tộc xâm chiếm. Lục đạo tông phái sau khi dàn xếp với Cửu Quốc Minh phải xuất lực nếu khu vực này bị uy hiếp.","detail":"Chín nước là địa bàn liên quan đến Cửu Quốc Minh trong hậu diễn biến Thiên Nam. Sau khi lục đạo tông phái dàn xếp với Cửu Quốc Minh, họ vẫn phải tranh địa bàn, linh mạch, linh quáng và không thể đứng ngoài nếu tu sĩ Mộ Lan muốn xâm chiếm nơi này.","theLucLienQuan":["Cửu Quốc Minh","Lục đạo tông phái","Mộ Lan gia tộc"],"nguon":["@c0363"]}]};
